import { GoogleGenAI, Modality, LiveServerMessage } from '@google/genai';
import { X, Mic, PhoneOff, Activity, Hexagon, Loader2, ArrowRight, AlertTriangle, RefreshCcw, ShieldAlert, Zap, CheckCircle2, UserPlus, CreditCard, Mail, Lock, Key } from 'lucide-react';
