export enum SoundType {
  IDLE = 'idle',
  HOVER = 'hover',
  FLIP = 'flip',
  WARP = 'warp',
  CLICK = 'click'
}

class KryptonSoundEngine {
  private ctx: AudioContext | null = null;
  private isEnabled: boolean = true;
  private masterGain: GainNode | null = null;
  private idleNodes: Map<string, { osc: OscillatorNode; gain: GainNode }> = new Map();

  constructor() {
    if (typeof window !== 'undefined') {
      // Initialize on first interaction to comply with browser policies
      window.addEventListener('click', () => this.init(), { once: true });
    }
  }

  private init() {
    if (this.ctx) return;
    this.ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
    this.masterGain = this.ctx.createGain();
    this.masterGain.gain.value = 0.15; // Set global volume
    this.masterGain.connect(this.ctx.destination);

    if (this.ctx.state === 'suspended') {
      this.ctx.resume();
    }
  }

  public setEnabled(enabled: boolean) {
    this.isEnabled = enabled;
  }

  private async ensureCtx() {
    if (!this.ctx) this.init();
    if (this.ctx?.state === 'suspended') await this.ctx.resume();
  }

  // Synthesis for "Whoosh" / Flip effect
  public async playFlip() {
    if (!this.isEnabled || !this.ctx) return;
    await this.ensureCtx();

    const noise = this.ctx.createBufferSource();
    const bufferSize = this.ctx.sampleRate * 1.0;
    const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
      data[i] = Math.random() * 2 - 1;
    }
    noise.buffer = buffer;

    const filter = this.ctx.createBiquadFilter();
    filter.type = 'bandpass';
    filter.frequency.setValueAtTime(100, this.ctx.currentTime);
    filter.frequency.exponentialRampToValueAtTime(3000, this.ctx.currentTime + 0.4);
    filter.frequency.exponentialRampToValueAtTime(100, this.ctx.currentTime + 0.9);
    filter.Q.value = 5;

    const gain = this.ctx.createGain();
    gain.gain.setValueAtTime(0, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0.2, this.ctx.currentTime + 0.4);
    gain.gain.linearRampToValueAtTime(0, this.ctx.currentTime + 0.9);

    noise.connect(filter);
    filter.connect(gain);
    gain.connect(this.masterGain!);

    noise.start();
    noise.stop(this.ctx.currentTime + 1);
  }

  // Synthesis for "Hover" activation riser
  public async playHover(gateId: string) {
    if (!this.isEnabled || !this.ctx) return;
    await this.ensureCtx();

    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    // Frequency signature per gate
    let freq = 200;
    if (gateId === 'TERRA') freq = 120;
    if (gateId === 'MARS') freq = 220;
    if (gateId === 'KRYPTON') freq = 350;
    if (gateId === 'GALAXY') freq = 180;

    osc.type = gateId === 'KRYPTON' ? 'sawtooth' : 'sine';
    osc.frequency.setValueAtTime(freq, this.ctx.currentTime);
    osc.frequency.linearRampToValueAtTime(freq * 1.5, this.ctx.currentTime + 0.6);

    const filter = this.ctx.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.value = 800;

    gain.gain.setValueAtTime(0, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0.1, this.ctx.currentTime + 0.1);
    gain.gain.linearRampToValueAtTime(0, this.ctx.currentTime + 0.6);

    osc.connect(filter);
    filter.connect(gain);
    gain.connect(this.masterGain!);

    osc.start();
    osc.stop(this.ctx.currentTime + 0.6);
  }

  // "Warp" transition sound for GateTransition
  public async playWarp() {
    if (!this.isEnabled || !this.ctx) return;
    await this.ensureCtx();

    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();
    const filter = this.ctx.createBiquadFilter();

    osc.type = 'sine';
    osc.frequency.setValueAtTime(800, this.ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(40, this.ctx.currentTime + 2);

    filter.type = 'lowpass';
    filter.Q.value = 15;
    filter.frequency.setValueAtTime(2000, this.ctx.currentTime);
    filter.frequency.exponentialRampToValueAtTime(200, this.ctx.currentTime + 2);

    gain.gain.setValueAtTime(0, this.ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0.3, this.ctx.currentTime + 0.2);
    gain.gain.exponentialRampToValueAtTime(0.001, this.ctx.currentTime + 2);

    osc.connect(filter);
    filter.connect(gain);
    gain.connect(this.masterGain!);

    osc.start();
    osc.stop(this.ctx.currentTime + 2.1);
  }

  public async playClick() {
    if (!this.isEnabled || !this.ctx) return;
    await this.ensureCtx();

    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    osc.type = 'sine';
    osc.frequency.setValueAtTime(1000, this.ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + 0.3);

    gain.gain.setValueAtTime(0.2, this.ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.001, this.ctx.currentTime + 0.3);

    osc.connect(gain);
    gain.connect(this.masterGain!);

    osc.start();
    osc.stop(this.ctx.currentTime + 0.3);
  }
}

export const soundEngine = new KryptonSoundEngine();

import React, { useEffect, useState } from 'react';
import { GATE_THEMES } from '../constants';
import { soundEngine } from '../utils/SoundEngine';

interface GateTransitionProps {
  gate: string;
  onComplete: () => void;
}

const GateTransition: React.FC<GateTransitionProps> = ({ gate, onComplete }) => {
  const theme = GATE_THEMES[gate] || GATE_THEMES.MARS;
  const [phase, setPhase] = useState<'init' | 'warp' | 'exit'>('init');

  useEffect(() => {
    // Trigger Warp Sound
    soundEngine.playWarp();

