interface ClientDashboardPageProps {
  onNavigate: (p: Page) => void;
  gate: string;
}

const ClientDashboardPage: React.FC<ClientDashboardPageProps> = ({ onNavigate, gate }) => {
  const [loading, setLoading] = useState(true);
  const [chatOpen, setChatOpen] = useState(false);
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const timer = setTimeout(() => {
      setLoading(false);
      // Initial message from FIKO
      setMessages([{
        role: 'model',
        text: `Bienvenue. Votre projet Porte ${gate} est bien enregistré dans nos systèmes. Je suis votre point de contact projet dédié. Comment puis-je vous éclairer aujourd'hui sur les prochaines étapes ?`
      }]);
    }, 2000);
    return () => clearTimeout(timer);
  }, [gate]);

  useEffect(() => {
    scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
  }, [messages, isTyping]);

  const handleSend = async () => {
    if (!input.trim() || isTyping) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsTyping(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [...messages, { role: 'user', text: userMsg }].map(m => ({
          role: m.role,
          parts: [{ text: m.text }]
        })),
        config: {
          systemInstruction: FIKO_ONBOARDING_PROMPT + `\nLe client a choisi la PORTE ${gate}.`,
          temperature: 0.7,
        }
      });

      const aiText = response.text || "Une erreur de liaison neurale est survenue.";
      setMessages(prev => [...prev, { role: 'model', text: aiText }]);
    } catch (error) {
      console.error(error);
      setMessages(prev => [...prev, { role: 'model', text: "Liaison saturée. Je reste à votre écoute pour la suite." }]);
    } finally {
      setIsTyping(false);
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-[#0B0B0F] flex flex-col items-center justify-center gap-8">
        <div className="relative">
          <Hexagon size={80} className="text-[#E10600] animate-[spin_4s_linear_infinite]" />
          <div className="absolute inset-0 flex items-center justify-center">
            <Zap size={24} className="text-[#E10600] animate-pulse" />
          </div>
        </div>
        <p className="text-[10px] font-black uppercase tracking-[0.6em] text-[#E10600] animate-pulse">Initialisation de l'Espace Porte {gate}...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#0B0B0F] pt-32 pb-20 px-6 lg:px-20 relative overflow-hidden">
      <div className="absolute inset-0 hex-bg opacity-[0.03] pointer-events-none"></div>
      <div className="absolute top-0 right-0 w-[800px] h-[800px] bg-[#E10600]/5 blur-[200px] rounded-full -translate-y-1/2 translate-x-1/2 pointer-events-none"></div>

      <div className="max-w-7xl mx-auto relative z-10">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-end mb-16 gap-8">
          <div>
            <div className="flex items-center gap-3 mb-4">
              <span className="size-2 bg-emerald-500 rounded-full animate-pulse"></span>
              <p className="text-[10px] font-black uppercase tracking-[0.4em] text-slate-500">CANAL CLIENT CRYPTÉ_ACTIVE</p>
            </div>
            <h1 className="text-4xl lg:text-6xl font-black uppercase tracking-tighter">
              ESPACE <span className="text-[#E10600]">PARTENAIRE.</span>
            </h1>
            <p className="text-slate-500 mt-4 text-[11px] font-black uppercase tracking-[0.3em] italic">Statut: Activation Immédiate de la Porte {gate}</p>
          </div>

          <div className="flex items-center gap-6">
            <button className="size-12 bg-white/5 border border-white/10 rounded-full flex items-center justify-center text-slate-400 hover:text-white transition-all relative">
              <Bell size={20} />
              <span className="absolute top-0 right-0 size-3 bg-[#E10600] rounded-full border-2 border-[#0B0B0F]"></span>
            </button>
            <div className="h-12 w-px bg-white/10"></div>
            <div className="flex items-center gap-4">
              <div className="text-right">
                <p className="text-[9px] font-black uppercase text-slate-500 tracking-widest">Client ID</p>
                <p className="text-xs font-mono font-bold text-white uppercase">K-{gate.slice(0,3)}-{Math.floor(Math.random()*9000)+1000}</p>
              </div>
              <div className="size-12 bg-[#E10600] border border-white/20 rounded-sm flex items-center justify-center font-black text-white">
                K
              </div>
            </div>
          </div>
        </div>

        <div className="grid lg:grid-cols-3 gap-8">
          <div className="lg:col-span-2 space-y-8">
            <div className="bg-[#1A1A1F] border border-[#E10600]/30 p-12 relative overflow-hidden group shadow-2xl">
              <div className="absolute top-0 right-0 p-8 opacity-[0.02] pointer-events-none group-hover:scale-110 transition-transform duration-1000">
                <Rocket size={200} />
              </div>

              <div className="flex justify-between items-start mb-12">
                <div>
                  <h3 className="text-[10px] font-black uppercase tracking-[0.5em] text-[#E10600] mb-2">ORDRE DE MISSION</h3>
                  <h4 className="text-3xl font-black uppercase tracking-tight text-white">DÉPLOIEMENT PORTE {gate}</h4>
                </div>
                <div className="px-6 py-2 border border-yellow-500/30 bg-yellow-500/5 text-yellow-500 text-[9px] font-black uppercase tracking-widest flex items-center gap-3">
                  <Clock size={14} className="animate-spin-slow" /> PAIEMENT EN VALIDATION
                </div>
              </div>

              <div className="relative py-10">
                <div className="absolute top-1/2 left-0 w-full h-px bg-white/10 -translate-y-1/2"></div>
                <div className="absolute top-1/2 left-0 w-1/4 h-1 bg-[#E10600] -translate-y-1/2 shadow-[0_0_15px_#E10600]"></div>

                <div className="relative flex justify-between">
                  {[
                    { label: 'SOUMISSION', active: true, done: true },
                    { label: 'PAIEMENT', active: true, done: false },
                    { label: 'DÉPLOIEMENT', active: false, done: false },
