                  ].map((s, i) => (
                    <div key={i} className="flex flex-col items-center gap-4 bg-[#1A1A1F] px-4">
                      <div className={`size-8 rounded-full border-2 flex items-center justify-center transition-all ${
                        s.done ? 'bg-[#E10600] border-[#E10600]' : s.active ? 'border-[#E10600] animate-pulse' : 'border-white/10'
                      }`}>
                        {s.done && <ShieldCheck size={14} className="text-white" />}
                      </div>
                      <span className={`text-[9px] font-black uppercase tracking-widest ${s.active ? 'text-white' : 'text-slate-600'}`}>{s.label}</span>
                    </div>
                  ))}
                </div>
              </div>

              <div className="mt-12 pt-12 border-t border-white/5 grid md:grid-cols-2 gap-10">
                <div className="p-6 bg-black/40 border border-white/5 space-y-4">
                  <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest">MESSAGE SYSTÈME</p>
                  <p className="text-sm font-bold text-white leading-relaxed italic">"Traitement de votre preuve de virement. Nos analystes financiers synchronisent vos fonds."</p>
                </div>
                <div className="flex items-center justify-end gap-6">
                  <button className="bg-[#E10600] text-white px-10 py-5 font-black text-[10px] uppercase tracking-widest shadow-xl hover:bg-red-700 transition-all">Télécharger Reçu PDF</button>
                </div>
              </div>
            </div>

            <div className="grid md:grid-cols-3 gap-6">
              {[
                { label: 'CONTRATS', icon: <FileText size={20}/>, desc: 'Architecture Signée' },
                { label: 'NEURAL CONFIG', icon: <Settings size={20}/>, desc: 'Personnaliser FIKO™' },
                { label: 'URGENCE', icon: <MessageSquare size={20}/>, desc: 'Ligne Rouge FIKO' }
              ].map((a, i) => (
                <button key={i} className="p-8 bg-[#1A1A1F] border border-white/5 hover:border-white/20 transition-all text-left group">
                  <div className="text-[#E10600] mb-6 group-hover:scale-110 transition-transform">{a.icon}</div>
                  <h5 className="text-[11px] font-black uppercase tracking-widest text-white mb-2">{a.label}</h5>
                  <p className="text-[9px] text-slate-500 uppercase tracking-widest">{a.desc}</p>
                </button>
              ))}
            </div>
          </div>

          <div className="flex flex-col h-full">
            <div className="bg-[#1A1A1F] border border-white/10 p-10 flex flex-col h-full relative overflow-hidden">
               <div className="absolute inset-0 hex-bg opacity-10"></div>
               <div className="relative z-10 flex flex-col h-full">
                  <div className="flex items-center gap-6 mb-10">
                    <div className="size-16 bg-[#E10600]/10 border border-[#E10600]/30 rounded-sm flex items-center justify-center shadow-2xl">
                      <Hexagon size={32} className="text-[#E10600] animate-[spin_8s_linear_infinite]" />
                    </div>
                    <div>
                      <h5 className="text-lg font-black uppercase tracking-tighter text-white">FIKO™ PROJECT</h5>
                      <div className="flex items-center gap-2">
                         <div className="size-1.5 bg-emerald-500 rounded-full animate-pulse"></div>
                         <p className="text-[9px] font-black text-slate-500 uppercase tracking-[0.4em]">En Ligne</p>
                      </div>
                    </div>
                  </div>

                  <div ref={scrollRef} className="flex-grow overflow-y-auto space-y-6 mb-8 pr-2 custom-scrollbar">
                    {messages.map((m, i) => (
                      <div key={i} className={`flex ${m.role === 'model' ? 'justify-start' : 'justify-end'}`}>
                        <div className={`max-w-[85%] p-5 rounded-sm text-sm leading-relaxed ${
                          m.role === 'model' ? 'bg-white/5 border border-white/10 text-slate-300' : 'bg-[#E10600] text-white font-bold'
                        }`}>
                          {m.text}
                        </div>
                      </div>
                    ))}
                    {isTyping && (
                      <div className="flex justify-start">
