    if (!input.trim() || isTyping) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsTyping(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [...messages, { role: 'user', text: userMsg }].map(m => ({
          role: m.role,
          parts: [{ text: m.text }]
        })),
        config: {
          systemInstruction: FIKO_ONBOARDING_PROMPT + `\nLe client a choisi la PORTE ${gate}. Réponds comme un accompagnateur projet rassurant.`,
          temperature: 0.7,
        }
      });

      const aiText = response.text || "Une latence neurale est détectée. Je reste à l'écoute.";
      setMessages(prev => [...prev, { role: 'model', text: aiText }]);
