import React, { useState, useEffect, useRef } from 'react';
import { Page, Message, UserProfile } from '../types';
import { FIKO_ADMIN_PROMPT } from '../constants';
import { GoogleGenAI } from '@google/genai';
import { 
  Hexagon, 
  Activity, 
  Clock, 
  ShieldCheck, 
  FileText, 
  MessageSquare, 
  Settings,
  Bell,
  CreditCard,
  Rocket,
  Zap,
  Send,
  Bot,
  User,
  LogOut,
  LayoutDashboard,
  Users,
