} from 'lucide-react';

interface AdminDashboardPageProps {
  onNavigate: (p: Page) => void;
  user: UserProfile | null;
  onLogout: () => void;
}

const AdminDashboardPage: React.FC<AdminDashboardPageProps> = ({ onNavigate, user, onLogout }) => {
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<'overview' | 'clients' | 'projects' | 'orders' | 'ia'>('overview');
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const timer = setTimeout(() => {
      setLoading(false);
      setMessages([{
        role: 'model',
        text: `Salutations, Administrateur. Le noyau neural de Krypton AI est stable. 14 déploiements sont en cours, 3 paiements attendent votre validation. Que souhaitez-vous superviser ?`
      }]);
    }, 2000);
    return () => clearTimeout(timer);
  }, []);

  useEffect(() => {
    scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
  }, [messages, isTyping]);

  const handleSend = async () => {
    if (!input.trim() || isTyping) return;
    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsTyping(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [...messages, { role: 'user', text: userMsg }].map(m => ({
          role: m.role,
          parts: [{ text: m.text }]
        })),
        config: {
          systemInstruction: FIKO_ADMIN_PROMPT,
          temperature: 0.7,
        }
      });
      setMessages(prev => [...prev, { role: 'model', text: response.text || "Analyse en pause." }]);
    } catch (e) {
      setMessages(prev => [...prev, { role: 'model', text: "Erreur de liaison neurale." }]);
    } finally {
      setIsTyping(false);
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-[#0B0B0F] flex flex-col items-center justify-center gap-8">
        <Hexagon size={80} className="text-[#E10600] animate-[spin_4s_linear_infinite]" />
        <p className="text-[10px] font-black uppercase tracking-[0.6em] text-[#E10600] animate-pulse">Lancement du Cockpit de Pilotage Admin...</p>
      </div>
    );
