interface AuthPageProps {
  onLoginSuccess: (user: UserProfile) => void;
  onNavigate: (p: Page) => void;
}

const AuthPage: React.FC<AuthPageProps> = ({ onLoginSuccess, onNavigate }) => {
  const [mode, setMode] = useState<'login' | 'signup'>('login');
  const [role, setRole] = useState<UserRole>(UserRole.CLIENT);
  const [isLoading, setIsLoading] = useState(false);

  // Form State
  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    email: '',
    password: '',
    company: ''
  });

  const handlePasswordChange = (val: string) => {
    // Filtrer pour ne garder que les chiffres
    const numericValue = val.replace(/[^0-9]/g, '');
    setFormData({ ...formData, password: numericValue });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (formData.password.length < 4) {
      alert("Le code de sécurité doit comporter au moins 4 chiffres.");
      return;
    }
    setIsLoading(true);

    // Simulation d'une authentification
    setTimeout(() => {
      const mockUser: UserProfile = {
        id: Math.random().toString(36).substr(2, 9),
        firstName: formData.firstName || (role === 'admin' ? 'Admin' : 'Client'),
        lastName: formData.lastName || 'Krypton',
        email: formData.email,
        role: role,
        company: formData.company
      };
      setIsLoading(false);
      onLoginSuccess(mockUser);
    }, 2000);
  };

  return (
    <div className="min-h-screen bg-[#0B0B0F] flex flex-col items-center justify-center p-6 relative overflow-hidden">
      <div className="absolute inset-0 hex-bg opacity-10 pointer-events-none"></div>
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 size-[800px] bg-[#E10600]/5 blur-[200px] rounded-full pointer-events-none"></div>

