function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  // Use Int16Array properly on the data.buffer
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

interface VocalSalesOverlayProps {
  agent: Agent | null;
  onClose: () => void;
  onOpenCheckout: (porte: string) => void;
  initialPorte?: string;
  initialFlowStep?: FikoFlowStep;
}

const VocalSalesOverlay: React.FC<VocalSalesOverlayProps> = ({ agent, onClose, onOpenCheckout, initialPorte, initialFlowStep }) => {
  const [step, setStep] = useState<'pre_start' | 'connecting' | 'active'>('pre_start');
  const [flowStep, setFlowStep] = useState<FikoFlowStep>(initialFlowStep || FikoFlowStep.DISCOVERY);
  const [isActive, setIsActive] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [bars, setBars] = useState<number[]>(new Array(40).fill(5));
  const [leadScore, setLeadScore] = useState(initialPorte ? 60 : 0);
  const [transcription, setTranscription] = useState("");

  // Account Form
  const [emailInput, setEmailInput] = useState("");
  const [passwordInput, setPasswordInput] = useState("");
  const [selectedPorte, setSelectedPorte] = useState(initialPorte || "MARS");

  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const isClosingRef = useRef(false);

  useEffect(() => {
    return () => {
      stopSession();
    };
  }, []);

  const stopSession = useCallback(() => {
    isClosingRef.current = true;
    setIsActive(false);

    sourcesRef.current.forEach(s => { 
      try { s.stop(); } catch(e) {} 
    });
    sourcesRef.current.clear();

    if (inputAudioContextRef.current && inputAudioContextRef.current.state !== 'closed') {
      inputAudioContextRef.current.close().catch(() => {});
    }
    if (outputAudioContextRef.current && outputAudioContextRef.current.state !== 'closed') {
      outputAudioContextRef.current.close().catch(() => {});
    }

    if (sessionRef.current) { 
      try { sessionRef.current.close(); } catch(e) {} 
    }

    setBars(new Array(40).fill(5));
    isClosingRef.current = false;
  }, []);

  const startVocalSession = async () => {
    setStep('connecting');
    setError(null);
    try {
      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      if (inputCtx.state === 'suspended') await inputCtx.resume();
      if (outputCtx.state === 'suspended') await outputCtx.resume();

      inputAudioContextRef.current = inputCtx;
      outputAudioContextRef.current = outputCtx;

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setStep('active');
            setIsActive(true);
            const source = inputCtx.createMediaStreamSource(stream);
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              if (!isActive) return;
              const inputData = e.inputBuffer.getChannelData(0);
              const volume = inputData.reduce((acc, v) => acc + Math.abs(v), 0) / inputData.length;

              // Real-time visualization
              setBars(prev => prev.map(() => Math.floor(Math.random() * (volume * 800 + 5)) + 5));

              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) {
                int16[i] = inputData[i] * 32768;
              }
              const pcmBlob = {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000'
              };

              sessionPromise.then(session => {
                session.sendRealtimeInput({ media: pcmBlob });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputCtx.destination);

            // INITIAL PROMPT TO KICKSTART FIKO
            const introText = initialPorte 
              ? `L'utilisateur vient de choisir la PORTE ${initialPorte}. Saute la phase de découverte. Valide son choix stratégique et demande-lui poliment son email et un mot de passe (composé uniquement de chiffres) pour créer son compte sécurisé.`
              : `L'utilisateur initie une session de closing FIKO™. Lance ton diagnostic de qualification stratégique habituel. Identifie son goulot d'étranglement.`;

            sessionPromise.then(session => {
              session.sendRealtimeInput([{ text: introText }]);
            });
          },
          onmessage: async (m: LiveServerMessage) => {
            // Handle Transcription
            if (m.serverContent?.inputTranscription) {
              setTranscription(m.serverContent.inputTranscription.text);
            }

            // Handle Audio Output
            const base64 = m.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64 && outputCtx.state !== 'closed') {
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputCtx.currentTime);
              const buffer = await decodeAudioData(decode(base64), outputCtx, 24000, 1);
              const source = outputCtx.createBufferSource();
              source.buffer = buffer;
              source.connect(outputCtx.destination);

              source.onended = () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setBars(new Array(40).fill(5));
              };

              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);

              // Increment lead score slightly with each model turn
              setLeadScore(prev => Math.min(prev + 5, 100));
            }

            // Interrupt handling
            if (m.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }

            // Step tracking (Simulated state update based on model logic if possible, 
            // but here we rely on manual navigation in the UI for the demo flow)
          },
          onerror: (e) => {
            console.error("Session error:", e);
            setError("LIAISON INTERROMPUE. VÉRIFIEZ VOTRE CONNEXION.");
            stopSession();
          },
          onclose: () => {
            if (!isClosingRef.current) stopSession();
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } }
          },
          systemInstruction: agent?.systemPrompt || ""
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (e) { 
      console.error(e);
      setError("ACCÈS MICRO REFUSÉ PAR LE SYSTÈME."); 
      setStep('pre_start'); 
    }
  };

  const handleAccountSubmit = () => {
    if (emailInput.includes("@") && passwordInput.length >= 4) {
      setFlowStep(FikoFlowStep.OFFER_CONFIRMATION);
      sessionRef.current?.sendRealtimeInput([{ text: `Le compte est créé. Email : ${emailInput}. Procède maintenant au récapitulatif de l'offre Porte ${selectedPorte} et propose de finaliser la commande.` }]);
    }
  };

  const handlePasswordInput = (val: string) => {
    const numericValue = val.replace(/[^0-9]/g, '');
    setPasswordInput(numericValue);
  };

  if (!agent) return null;

  return (
    <div className="fixed inset-0 z-[100] bg-black flex flex-col items-center justify-center animate-in fade-in duration-1000 p-6">
      <div className="absolute inset-0 hex-bg opacity-10"></div>

      {/* CLOSE BUTTON - TOP RIGHT */}
