        <X size={44} className="group-hover:rotate-90 transition-transform" />
      </button>

      {/* PROGRESS FLOW VISUALIZER */}
      <div className="absolute top-12 left-1/2 -translate-x-1/2 w-full max-w-2xl z-50 flex justify-between px-10">
        {[
          { id: FikoFlowStep.DISCOVERY, label: 'DÉCOUVERTE' },
          { id: FikoFlowStep.CLOSING_VALIDATION, label: 'VALIDATION' },
          { id: FikoFlowStep.ACCOUNT_CREATION, label: 'COMPTE' },
          { id: FikoFlowStep.OFFER_CONFIRMATION, label: 'OFFRE' }
        ].map((s, i) => (
          <div key={i} className={`flex flex-col items-center gap-3 transition-opacity duration-500 ${flowStep === s.id ? 'opacity-100' : 'opacity-20'}`}>
            <div className={`size-10 rounded-full border-2 flex items-center justify-center text-xs font-black ${flowStep === s.id ? 'bg-[#E10600] border-[#E10600] shadow-[0_0_20px_#E10600]' : 'border-white/20'}`}>{i+1}</div>
            <span className="text-[10px] font-black tracking-[0.2em]">{s.label}</span>
          </div>
        ))}
      </div>

      {step === 'pre_start' && (
        <div className="text-center space-y-16 relative z-10 animate-in zoom-in-95">
          <div className="flex flex-col items-center gap-8">
             <Hexagon size={120} className="text-[#E10600] animate-[spin_10s_linear_infinite]" strokeWidth={1} />
             <h2 className="text-6xl lg:text-[100px] font-black uppercase tracking-tighter text-white leading-none">
               {initialPorte ? `Porte ${initialPorte}` : 'Session'} <br/> <span className="text-[#E10600]">FIKO™.</span>
             </h2>
          </div>
          <button 
            onClick={startVocalSession} 
            className="group bg-[#E10600] text-white px-20 py-10 font-black text-xs uppercase tracking-[0.5em] shadow-[0_40px_100px_rgba(225,6,0,0.3)] flex items-center gap-8 mx-auto hover:scale-105 active:scale-95 transition-all"
          >
             🎙️ INITIALISER LE CLOSING VOCAL
          </button>
          <p className="text-[10px] text-slate-600 uppercase tracking-[0.4em] font-black">Liaison chiffrée Krypton-Net active</p>
        </div>
      )}

      {step === 'connecting' && (
        <div className="flex flex-col items-center gap-12 animate-pulse">
           <Loader2 className="size-24 text-[#E10600] animate-spin" />
           <p className="text-2xl font-black uppercase tracking-[0.5em] text-white">Établissement du canal...</p>
