                    "{transcription}"
                 </div>
              )}
           </div>
        </div>
      )}

      {error && (
        <div className="fixed bottom-12 left-1/2 -translate-x-1/2 z-[150] animate-in slide-in-from-bottom-8">
           <div className="bg-[#E10600] border border-white/20 p-8 rounded-sm flex items-center gap-8 shadow-[0_0_100px_rgba(225,6,0,0.5)]">
