              <div className="relative group">
                <Mail className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-600 group-focus-within:text-white transition-colors" size={18} />
                <input 
                  required
                  type="email" 
                  placeholder="VOTRE EMAIL PROFESSIONNEL" 
                  value={email}
                  onChange={e => setEmail(e.target.value)}
                  className="w-full bg-black border border-white/5 p-6 pl-16 text-white text-xs font-black uppercase tracking-widest outline-none focus:border-white/20 transition-all"
                />
              </div>
              <div className="relative group">
                <Hash className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-600 group-focus-within:text-white transition-colors" size={18} />
                <input 
                  required
                  type="password" 
                  inputMode="numeric"
                  pattern="[0-9]*"
                  placeholder="CODE DE SÉCURITÉ (CHIFFRES)" 
                  value={password}
                  onChange={e => handlePasswordChange(e.target.value)}
                  className="w-full bg-black border border-white/5 p-6 pl-16 text-white text-xs font-black uppercase tracking-widest outline-none focus:border-white/20 transition-all"
                />
              </div>
              <p className="text-[8px] text-slate-600 uppercase tracking-[0.3em] font-black ml-2">Le mot de passe doit être numérique (0-9).</p>
            </div>

            <button 
              type="submit"
              disabled={isLoading || password.length < 4}
              className="w-full py-8 text-white font-black text-xs uppercase tracking-[0.5em] transition-all flex items-center justify-center gap-6 relative group overflow-hidden disabled:opacity-30"
              style={{ backgroundColor: theme.color }}
