  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const timer = setTimeout(() => {
      setLoading(false);
      setMessages([{
        role: 'model',
        text: `Bienvenue. Voici l’état actuel de Krypton AI. Souhaitez-vous analyser les performances, superviser l’exécution, ou prendre une décision stratégique ?`
      }]);
    }, 2000);
    return () => clearTimeout(timer);
  }, []);

  useEffect(() => {
    scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
  }, [messages, isTyping]);

  const handleSend = async () => {
    if (!input.trim() || isTyping) return;
    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsTyping(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [...messages, { role: 'user', text: userMsg }].map(m => ({
          role: m.role,
          parts: [{ text: m.text }]
        })),
        config: {
          systemInstruction: FIKO_SUPER_ADMIN_PROMPT,
          temperature: 0.7,
        }
      });
      setMessages(prev => [...prev, { role: 'model', text: response.text || "Analyse interrompue." }]);
    } catch (e) {
      setMessages(prev => [...prev, { role: 'model', text: "Liaison neurale saturée." }]);
    } finally {
      setIsTyping(false);
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-[#0B0B0F] flex flex-col items-center justify-center gap-8">
        <div className="relative">
           <Hexagon size={80} className="text-[#E10600] animate-[spin_4s_linear_infinite]" />
           <Crown size={24} className="absolute inset-0 m-auto text-white" />
        </div>
        <p className="text-[10px] font-black uppercase tracking-[0.6em] text-[#E10600] animate-pulse">Lancement du Cockpit Super Admin...</p>
      </div>
    );
  }

  const sidebarItems = [
    { id: 'overview', label: 'Vue Globale', icon: <LayoutDashboard size={18} /> },
    { id: 'gates', label: 'Portes & Offres', icon: <DoorOpen size={18} /> },
    { id: 'users', label: 'Utilisateurs', icon: <Users size={18} /> },
