import React, { useState, useCallback, useEffect } from 'react';
import { Page, FikoFlowStep, UserProfile, UserRole } from './types';
import { GLOBAL_ADVISOR, MASTER_AGENTS } from './constants';
import { soundEngine } from './utils/SoundEngine';
import Navbar from './components/Navbar';
import Footer from './components/Footer';
import HomePage from './pages/HomePage';
import AgentsPage from './pages/AgentsPage';
import VoicePage from './pages/VoicePage';
import CRMPage from './pages/CRMPage';
import ScraperPage from './pages/ScraperPage';
import TrustPage from './pages/TrustPage';
import PricingPage from './pages/PricingPage';
import ClientDashboardPage from './pages/ClientDashboardPage';
import AdminDashboardPage from './pages/AdminDashboardPage';
import AuthPage from './pages/AuthPage';
import AIChatOverlay from './components/AIChatOverlay';
import VocalSalesOverlay from './components/VocalSalesOverlay';
import OrderModal from './components/OrderModal';
import GateTransition from './components/GateTransition';
import GateAuthModal from './components/GateAuthModal';
import { Hexagon, Volume2, VolumeX } from 'lucide-react';

const App: React.FC = () => {
  // Authentication & User State
  const [user, setUser] = useState<UserProfile | null>(null);

  // Routing state
  const [currentPage, setCurrentPage] = useState<Page>(Page.HOME);
  const [globalAdvisorOpen, setGlobalAdvisorOpen] = useState(false);
  const [soundEnabled, setSoundEnabled] = useState(true);

  // Fiko / Flows state
  const [fikoVocal, setFikoVocal] = useState<{ open: boolean; porte?: string; initialStep?: FikoFlowStep }>({
    open: false
  });

  // Gate Flow state
  const [activeGateTransition, setActiveGateTransition] = useState<string | null>(null);
  const [showGateAuth, setShowGateAuth] = useState<string | null>(null);
  const [orderModal, setOrderModal] = useState<{ open: boolean; porte: string }>({ open: false, porte: '' });
  const [selectedGate, setSelectedGate] = useState<string>('MARS');

  useEffect(() => {
    soundEngine.setEnabled(soundEnabled);
  }, [soundEnabled]);

  const navigateTo = (page: Page) => {
    setCurrentPage(page);
    window.scrollTo(0, 0);
  };

  const handleLoginSuccess = (profile: UserProfile) => {
    setUser(profile);
    if (profile.role === UserRole.SUPER_ADMIN || profile.role === UserRole.ADMIN) {
      navigateTo(Page.ADMIN_DASHBOARD);
    } else {
      navigateTo(Page.CLIENT_DASHBOARD);
    }
  };

  const handleLogout = () => {
    setUser(null);
    navigateTo(Page.HOME);
  };

  const openFikoVocal = (porte?: string, initialStep?: FikoFlowStep) => {
    setFikoVocal({ open: true, porte, initialStep });
  };

  const handleGateChoice = (gate: string) => {
    setActiveGateTransition(gate);
    setSelectedGate(gate);
  };

  const handleTransitionComplete = useCallback(() => {
    const gate = activeGateTransition;
    setActiveGateTransition(null);
    setShowGateAuth(gate);
  }, [activeGateTransition]);

  const handleAuthSuccess = () => {
    const gate = showGateAuth || 'MARS';
    setShowGateAuth(null);
    setOrderModal({ open: true, porte: gate });
  };

  const handleOrderComplete = (porte: string) => {
    setOrderModal({ open: false, porte: '' });
    setSelectedGate(porte);
    navigateTo(Page.CLIENT_DASHBOARD);
  };

  const handleOpenCheckout = (porte: string) => {
    setFikoVocal({ open: false });
    setOrderModal({ open: true, porte });
    setSelectedGate(porte);
  };

  const renderPage = () => {
    switch (currentPage) {
      case Page.HOME: return <HomePage onNavigate={navigateTo} onOpenFiko={() => openFikoVocal()} />;
      case Page.AGENTS: return <AgentsPage onOpenFiko={() => openFikoVocal()} />;
      case Page.VOICE: return <VoicePage />;
      case Page.CRM: return <CRMPage />;
      case Page.SCRAPER: return <ScraperPage />;
      case Page.PRICING: return <PricingPage onNavigate={navigateTo} onOpenFiko={handleGateChoice} />;
      case Page.TRUST: return <TrustPage />;
      case Page.CLIENT_DASHBOARD: return <ClientDashboardPage onNavigate={navigateTo} gate={selectedGate} />;
      case Page.ADMIN_DASHBOARD: return <AdminDashboardPage onNavigate={navigateTo} user={user} onLogout={handleLogout} />;
      case Page.AUTH: return <AuthPage onLoginSuccess={handleLoginSuccess} onNavigate={navigateTo} />;
      default: return <HomePage onNavigate={navigateTo} onOpenFiko={() => openFikoVocal()} />;
    }
  };

  const isFullImmersion = currentPage === Page.CLIENT_DASHBOARD || currentPage === Page.ADMIN_DASHBOARD || currentPage === Page.AUTH;

  return (
    <div className="min-h-screen bg-[#0B0B0F] text-white flex flex-col selection:bg-[#E10600] selection:text-white font-sans overflow-x-hidden">
      {!isFullImmersion && (
        <Navbar 
          activePage={currentPage} 
          onNavigate={navigateTo}
          user={user}
          onLogout={handleLogout}
        />
      )}

      <main className="flex-grow">
        {renderPage()}
      </main>

      {!isFullImmersion && <Footer onNavigate={navigateTo} />}

      {!isFullImmersion && (
        <div className="fixed bottom-2 right-2 z-50 flex flex-col items-center gap-4 scale-90 lg:scale-100">
          <button 
            onClick={() => setSoundEnabled(!soundEnabled)}
            className="size-12 bg-white/5 border border-white/10 rounded-full flex items-center justify-center text-slate-500 hover:text-white transition-all hover:bg-white/10"
          >
            {soundEnabled ? <Volume2 size={18} /> : <VolumeX size={18} />}
          </button>

          <button 
            onClick={() => openFikoVocal()}
            className="relative group flex items-center justify-center p-6 transition-all hover:scale-110 active:scale-95"
            aria-label="Lancer la session vocale FIKO™"
          >
            <div className="absolute inset-0 bg-[#E10600]/30 blur-[45px] rounded-full group-hover:bg-[#E10600]/60 transition-all duration-700 animate-pulse"></div>

            <div className="relative flex items-center justify-center">
              <Hexagon size={100} className="text-[#E10600]/40 animate-hex-orbit" strokeWidth={1} />
              <Hexagon size={72} className="absolute text-[#E10600] drop-shadow-[0_0_25px_rgba(225,6,0,1)]" strokeWidth={3} fill="#0B0B0F" />
              <div className="absolute flex flex-col items-center justify-center pointer-events-none">
                <span className="text-[14px] font-black tracking-[0.05em] text-white uppercase neon-fiko drop-shadow-[0_0_8px_rgba(0,0,0,1)]">
                  FIKO™
                </span>
              </div>
            </div>
          </button>
        </div>
      )}

      {globalAdvisorOpen && (
        <AIChatOverlay agent={GLOBAL_ADVISOR} onClose={() => setGlobalAdvisorOpen(false)} />
      )}

      {fikoVocal.open && (
        <VocalSalesOverlay 
          agent={MASTER_AGENTS[0]} 
          onClose={() => setFikoVocal({ open: false })} 
          onOpenCheckout={handleOpenCheckout}
          initialPorte={fikoVocal.porte}
          initialFlowStep={fikoVocal.initialStep}
        />
      )}

      {activeGateTransition && (
        <GateTransition 
          gate={activeGateTransition} 
          onComplete={handleTransitionComplete} 
        />
      )}

      {showGateAuth && (
        <GateAuthModal 
          gate={showGateAuth} 
          onSuccess={handleAuthSuccess} 
          onClose={() => setShowGateAuth(null)} 
        />
      )}

      {orderModal.open && (
        <OrderModal 
          porte={orderModal.porte} 
          onClose={() => setOrderModal({ open: false, porte: '' })} 
          onComplete={handleOrderComplete}
        />
      )}
    </div>
  );
};

export default App;

