import React, { useState } from 'react';
import { Page, UserRole, UserProfile } from '../types';
import { Mail, Lock, User, ArrowRight, ShieldCheck, Rocket, ChevronLeft, Building2, Hash, Crown, Shield } from 'lucide-react';

interface AuthPageProps {
  onLoginSuccess: (user: UserProfile) => void;
  onNavigate: (p: Page) => void;
}

const AuthPage: React.FC<AuthPageProps> = ({ onLoginSuccess, onNavigate }) => {
  const [mode, setMode] = useState<'login' | 'signup'>('login');
  const [role, setRole] = useState<UserRole>(UserRole.CLIENT);
  const [isLoading, setIsLoading] = useState(false);

  // Form State
  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    email: '',
    password: '',
    company: ''
  });

  const handlePasswordChange = (val: string) => {
    const numericValue = val.replace(/[^0-9]/g, '');
    setFormData({ ...formData, password: numericValue });
  };

  const handleQuickLogin = (targetRole: UserRole) => {
    setIsLoading(true);
    setTimeout(() => {
      const mockUser: UserProfile = {
        id: 'DEMO-' + Math.random().toString(36).substr(2, 4).toUpperCase(),
        firstName: targetRole === UserRole.SUPER_ADMIN ? 'Super' : targetRole === UserRole.ADMIN ? 'Admin' : 'Client',
        lastName: 'Demo',
        email: `${targetRole.toLowerCase()}@krypton.ai`,
        role: targetRole,
        company: 'Krypton AI Systems'
      };
      setIsLoading(false);
      onLoginSuccess(mockUser);
    }, 1000);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (formData.password.length < 4) {
      alert("Le code de sécurité doit comporter au moins 4 chiffres.");
      return;
    }
    setIsLoading(true);

    setTimeout(() => {
      const mockUser: UserProfile = {
        id: Math.random().toString(36).substr(2, 9),
        firstName: formData.firstName || (role === UserRole.SUPER_ADMIN ? 'SuperAdmin' : role === UserRole.ADMIN ? 'Admin' : 'Client'),
        lastName: formData.lastName || 'Krypton',
        email: formData.email,
        role: role,
        company: formData.company
      };
      setIsLoading(false);
      onLoginSuccess(mockUser);
    }, 2000);
  };

  return (
    <div className="min-h-screen bg-[#0B0B0F] flex flex-col items-center justify-center p-6 relative overflow-hidden">
      <div className="absolute inset-0 hex-bg opacity-10 pointer-events-none"></div>
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 size-[800px] bg-[#E10600]/5 blur-[200px] rounded-full pointer-events-none"></div>

      <button 
        onClick={() => onNavigate(Page.HOME)}
        className="absolute top-12 left-12 flex items-center gap-3 text-slate-500 hover:text-white transition-colors group z-20"
      >
        <ChevronLeft size={20} className="group-hover:-translate-x-1 transition-transform" />
        <span className="text-[10px] font-black uppercase tracking-widest">Retour Accueil</span>
      </button>

      <div className="w-full max-w-xl bg-[#1A1A1F] border border-white/5 p-12 lg:p-16 relative z-10 shadow-2xl">
        <div className="h-1.5 absolute top-0 left-0 w-full bg-gradient-to-r from-[#E10600] to-red-900"></div>

        <div className="text-center mb-10">
          <div className="size-16 bg-[#E10600] rounded-sm flex items-center justify-center mx-auto mb-8 shadow-xl shadow-red-500/20">
            <Rocket className="text-white" size={32} />
          </div>
          <h1 className="text-3xl font-black uppercase tracking-tighter mb-2">
            {mode === 'login' ? 'ACCÈS SÉCURISÉ' : 'REJOINDRE KRYPTON'}
          </h1>
          <p className="text-slate-500 text-[9px] font-black uppercase tracking-[0.4em]">Propulsé par Koffmann Group</p>
        </div>

        {/* QUICK LOGIN BUTTONS (Available only in Login mode) */}
        {mode === 'login' && (
          <div className="mb-10 space-y-4">
            <p className="text-[8px] font-black text-slate-600 uppercase tracking-[0.3em] mb-4 text-center">Accès Rapide (Démo)</p>
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
              <button 
                onClick={() => handleQuickLogin(UserRole.CLIENT)}
                className="flex items-center justify-center gap-2 py-3 bg-white/5 border border-white/10 hover:border-emerald-500/50 hover:bg-emerald-500/5 text-[9px] font-black uppercase tracking-widest transition-all text-slate-400 hover:text-white"
              >
                <User size={12} /> Client
              </button>
              <button 
                onClick={() => handleQuickLogin(UserRole.ADMIN)}
                className="flex items-center justify-center gap-2 py-3 bg-white/5 border border-white/10 hover:border-[#E10600]/50 hover:bg-[#E10600]/5 text-[9px] font-black uppercase tracking-widest transition-all text-slate-400 hover:text-white"
              >
                <Shield size={12} /> Admin
              </button>
              <button 
                onClick={() => handleQuickLogin(UserRole.SUPER_ADMIN)}
                className="flex items-center justify-center gap-2 py-3 bg-white/5 border border-white/10 hover:border-yellow-500/50 hover:bg-yellow-500/5 text-[9px] font-black uppercase tracking-widest transition-all text-slate-400 hover:text-white"
              >
                <Crown size={12} /> CEO
              </button>
            </div>
            <div className="flex items-center gap-4 py-6">
              <div className="h-px flex-grow bg-white/5"></div>
              <span className="text-[8px] font-black text-slate-700 uppercase tracking-widest">Ou via identifiants</span>
              <div className="h-px flex-grow bg-white/5"></div>
            </div>
          </div>
        )}

        {/* ROLE TOGGLE IF SIGNUP */}
        {mode === 'signup' && (
          <div className="flex flex-wrap gap-2 mb-8">
            <button 
              type="button"
              onClick={() => setRole(UserRole.CLIENT)}
              className={`flex-grow py-3 border text-[8px] font-black uppercase tracking-widest transition-all ${role === UserRole.CLIENT ? 'border-[#E10600] text-[#E10600] bg-[#E10600]/5' : 'border-white/5 text-slate-600'}`}
            >
              CLIENT
            </button>
            <button 
              type="button"
              onClick={() => setRole(UserRole.ADMIN)}
              className={`flex-grow py-3 border text-[8px] font-black uppercase tracking-widest transition-all ${role === UserRole.ADMIN ? 'border-[#E10600] text-[#E10600] bg-[#E10600]/5' : 'border-white/5 text-slate-600'}`}
            >
              ADMIN
            </button>
            <button 
              type="button"
              onClick={() => setRole(UserRole.SUPER_ADMIN)}
              className={`flex-grow py-3 border text-[8px] font-black uppercase tracking-widest transition-all ${role === UserRole.SUPER_ADMIN ? 'border-[#E10600] text-[#E10600] bg-[#E10600]/5' : 'border-white/5 text-slate-600'}`}
            >
              SUPER ADMIN
            </button>
          </div>
        )}

        <form onSubmit={handleSubmit} className="space-y-5">
          {mode === 'signup' && (
            <div className="grid grid-cols-2 gap-4">
              <div className="relative group">
                <User className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-600" size={14} />
                <input 
                  required
                  placeholder="PRÉNOM"
                  className="w-full bg-black border border-white/5 p-4 pl-12 text-[9px] font-black uppercase tracking-widest text-white outline-none focus:border-[#E10600] transition-all"
                  value={formData.firstName}
                  onChange={e => setFormData({...formData, firstName: e.target.value})}
                />
              </div>
              <div className="relative group">
                <User className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-600" size={14} />
                <input 
                  required
                  placeholder="NOM"
                  className="w-full bg-black border border-white/5 p-4 pl-12 text-[9px] font-black uppercase tracking-widest text-white outline-none focus:border-[#E10600] transition-all"
                  value={formData.lastName}
                  onChange={e => setFormData({...formData, lastName: e.target.value})}
                />
              </div>
            </div>
          )}

          {mode === 'signup' && role === UserRole.CLIENT && (
            <div className="relative group">
              <Building2 className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-600" size={14} />
              <input 
                placeholder="ENTREPRISE"
                className="w-full bg-black border border-white/5 p-4 pl-12 text-[9px] font-black uppercase tracking-widest text-white outline-none focus:border-[#E10600] transition-all"
                value={formData.company}
                onChange={e => setFormData({...formData, company: e.target.value})}
              />
            </div>
          )}

          <div className="relative group">
            <Mail className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-600" size={14} />
            <input 
              required
              type="email"
              placeholder="VOTRE EMAIL"
              className="w-full bg-black border border-white/5 p-4 pl-12 text-[9px] font-black uppercase tracking-widest text-white outline-none focus:border-[#E10600] transition-all"
              value={formData.email}
              onChange={e => setFormData({...formData, email: e.target.value})}
            />
          </div>

          <div className="relative group">
            <Hash className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-600" size={14} />
            <input 
              required
              type="password"
              inputMode="numeric"
              pattern="[0-9]*"
              placeholder="CODE DE SÉCURITÉ (NUMÉRIQUE)"
              className="w-full bg-black border border-white/5 p-4 pl-12 text-[9px] font-black uppercase tracking-widest text-white outline-none focus:border-[#E10600] transition-all"
              value={formData.password}
              onChange={e => handlePasswordChange(e.target.value)}
            />
          </div>

          <button 
            type="submit"
            disabled={isLoading}
            className="w-full bg-[#E10600] hover:bg-red-700 py-5 text-white font-black text-[10px] uppercase tracking-[0.4em] transition-all flex items-center justify-center gap-4 relative overflow-hidden group shadow-xl shadow-red-500/20 active:scale-95"
          >
            {isLoading ? (
              <span className="size-4 border-2 border-white/20 border-t-white rounded-full animate-spin"></span>
            ) : (
              <>
                <span className="relative z-10">{mode === 'login' ? 'SE CONNECTER' : 'CRÉER MON COMPTE'}</span>
                <ArrowRight size={16} className="relative z-10 group-hover:translate-x-2 transition-transform" />
              </>
            )}
          </button>
        </form>

        <div className="mt-8 text-center space-y-6">
          <button 
            onClick={() => setMode(mode === 'login' ? 'signup' : 'login')}
            className="text-[9px] font-black uppercase tracking-widest text-slate-500 hover:text-white transition-all underline decoration-[#E10600]"
          >
            {mode === 'login' ? 'Pas encore de compte ? Créer mon espace' : 'Déjà un compte ? Se connecter'}
          </button>

          <div className="pt-6 border-t border-white/5 flex items-center justify-center gap-6 opacity-30">
            <div className="flex items-center gap-2 text-[8px] font-black uppercase tracking-widest">
              <ShieldCheck size={14} className="text-emerald-500" /> AES-512 SECURE
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

