  const [activeTab, setActiveTab] = useState<'overview' | 'gates' | 'users' | 'projects' | 'agents' | 'payments' | 'analytics' | 'logs' | 'settings' | 'crisis'>('overview');
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
