  const [alerts, setAlerts] = useState<PlatformAlert[]>([]);
  const [isCrisisMode, setIsCrisisMode] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const timer = setTimeout(() => {
      setLoading(false);
      setMessages([{
        role: 'model',
        text: `Bienvenue. Voici l’état actuel de Krypton AI. Souhaitez-vous analyser les performances, superviser l’exécution, ou prendre une décision stratégique ?`
      }]);

      // Simulation d'une alerte après quelques secondes pour le mode démo
      setTimeout(() => {
        const demoAlert: PlatformAlert = {
          id: 'ALRT-99',
          type: 'anomaly',
          severity: 'medium',
          title: 'BAISSE DE CONVERSION DÉTECTÉE',
          description: 'Le tunnel de la Porte MARS affiche une chute de 18% sur les dernières 2h.',
          timestamp: new Date().toLocaleTimeString(),
          impact: 'Perte estimée de 2.4M FCFA sur le flux quotidien.'
        };
        setAlerts([demoAlert]);
      }, 5000);
    }, 2000);
    return () => clearTimeout(timer);
  }, []);

  useEffect(() => {
    scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
  }, [messages, isTyping]);

  const handleSend = async () => {
    if (!input.trim() || isTyping) return;
    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsTyping(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      // On utilise le prompt CRISE si le mode est activé ou si des alertes critiques existent
      const systemPrompt = (isCrisisMode || alerts.some(a => a.severity === 'high')) 
        ? FIKO_CRISIS_ALERT_PROMPT 
        : FIKO_SUPER_ADMIN_PROMPT;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [...messages, { role: 'user', text: userMsg }].map(m => ({
          role: m.role,
          parts: [{ text: m.text }]
        })),
        config: {
          systemInstruction: systemPrompt,
          temperature: 0.5, // Plus bas pour le mode crise/admin pour plus de précision
        }
      });
      setMessages(prev => [...prev, { role: 'model', text: response.text || "Analyse interrompue." }]);
    } catch (e) {
      setMessages(prev => [...prev, { role: 'model', text: "Liaison neurale saturée." }]);
    } finally {
      setIsTyping(false);
    }
  };

  const toggleCrisisMode = () => {
    setIsCrisisMode(!isCrisisMode);
