interface AdminDashboardPageProps {
  onNavigate: (p: Page) => void;
  user: UserProfile | null;
  onLogout: () => void;
}

const AdminDashboardPage: React.FC<AdminDashboardPageProps> = ({ onNavigate, user, onLogout }) => {
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<'overview' | 'gates' | 'users' | 'projects' | 'agents' | 'payments' | 'analytics' | 'logs' | 'settings' | 'crisis' | 'optimization'>('overview');
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [alerts, setAlerts] = useState<PlatformAlert[]>([]);
  const [optimizations, setOptimizations] = useState<OptimizationSuggestion[]>([]);
  const [isCrisisMode, setIsCrisisMode] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const timer = setTimeout(() => {
      setLoading(false);
      setMessages([{
        role: 'model',
        text: `Bienvenue. Voici l’état actuel de Krypton AI. Souhaitez-vous analyser les performances, superviser l’exécution, ou prendre une décision stratégique ?`
      }]);

      // Simulation d'alertes et d'optimisations
      setTimeout(() => {
        setAlerts([{
          id: 'ALRT-99',
          type: 'anomaly',
          severity: 'medium',
          title: 'BAISSE DE CONVERSION DÉTECTÉE',
          description: 'Le tunnel de la Porte MARS affiche une chute de 18% sur les dernières 2h.',
          timestamp: new Date().toLocaleTimeString(),
          impact: 'Perte estimée de 2.4M FCFA sur le flux quotidien.'
        }]);

        setOptimizations([
          {
            id: 'OPT-01',
            category: 'conversion',
            observation: 'Taux d’abandon élevé (64%) après affichage du prix sur la Porte TERA.',
            impact: 'Potentiel de +12% de conversion sur les nouveaux leads.',
            action: 'Déplacer la section "Valeur Ajoutée" avant le tableau de prix pour renforcer la maturité client.',
            risk: 'low',
            status: 'pending'
          },
          {
            id: 'OPT-02',
            category: 'performance',
            observation: 'L’agent FIKO™ est moins engageant sur les questions dépassant 4 lignes.',
            impact: 'Fluidité conversationnelle accrue, temps de session réduit de 15%.',
            action: 'Ajuster les paramètres de concision de l’agent et forcer l’usage de listes à puces.',
            risk: 'low',
            status: 'pending'
          }
        ]);
      }, 3000);
    }, 2000);
    return () => clearTimeout(timer);
  }, []);

  useEffect(() => {
    scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
  }, [messages, isTyping]);

  const handleSend = async () => {
    if (!input.trim() || isTyping) return;
    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsTyping(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      let systemPrompt = FIKO_SUPER_ADMIN_PROMPT;
      if (isCrisisMode || alerts.some(a => a.severity === 'high')) {
        systemPrompt = FIKO_CRISIS_ALERT_PROMPT;
      } else if (activeTab === 'optimization') {
        systemPrompt = FIKO_AUTO_OPTIMIZATION_PROMPT;
      }

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [...messages, { role: 'user', text: userMsg }].map(m => ({
          role: m.role,
          parts: [{ text: m.text }]
        })),
        config: {
          systemInstruction: systemPrompt,
          temperature: activeTab === 'optimization' ? 0.3 : 0.5,
        }
      });
      setMessages(prev => [...prev, { role: 'model', text: response.text || "Analyse interrompue." }]);
    } catch (e) {
      setMessages(prev => [...prev, { role: 'model', text: "Liaison neurale saturée." }]);
    } finally {
      setIsTyping(false);
    }
  };

  const applyOptimization = (id: string) => {
    setOptimizations(prev => prev.map(o => o.id === id ? { ...o, status: 'applied' } : o));
    setMessages(prev => [...prev, { role: 'model', text: `Optimisation ${id} appliquée avec succès. Monitoring en cours pour mesurer l'impact.` }]);
  };

  const toggleCrisisMode = () => {
    setIsCrisisMode(!isCrisisMode);
    if (!isCrisisMode) {
      setMessages(prev => [...prev, { role: 'model', text: "MODE CRISE ACTIVÉ. Cellule stratégique en attente de directives." }]);
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-[#0B0B0F] flex flex-col items-center justify-center gap-8">
        <div className="relative">
           <Hexagon size={80} className="text-[#E10600] animate-[spin_4s_linear_infinite]" />
           <Crown size={24} className="absolute inset-0 m-auto text-white" />
        </div>
        <p className="text-[10px] font-black uppercase tracking-[0.6em] text-[#E10600] animate-pulse">Lancement du Cockpit Super Admin...</p>
      </div>
    );
  }

  const sidebarItems = [
    { id: 'overview', label: 'Vue Globale', icon: <LayoutDashboard size={18} /> },
    { id: 'optimization', label: 'Auto-Optimisation', icon: <Sparkles size={18} />, badge: optimizations.filter(o => o.status === 'pending').length.toString() },
    { id: 'crisis', label: 'Cellule de Crise', icon: <ShieldX size={18} />, badge: alerts.length > 0 ? alerts.length.toString() : undefined, highlight: alerts.length > 0 },
    { id: 'gates', label: 'Portes & Offres', icon: <DoorOpen size={18} /> },
    { id: 'users', label: 'Utilisateurs', icon: <Users size={18} /> },
    { id: 'projects', label: 'Projets', icon: <Briefcase size={18} />, badge: '14' },
    { id: 'agents', label: 'Agents IA', icon: <Bot size={18} /> },
    { id: 'payments', label: 'Paiements', icon: <CreditCard size={18} />, badge: '3' },
    { id: 'analytics', label: 'Analytics & KPI', icon: <BarChart size={18} /> },
    { id: 'logs', label: 'Logs & Audit', icon: <ShieldAlert size={18} /> },
    { id: 'settings', label: 'Paramètres', icon: <Settings size={18} /> },
  ];

  return (
    <div className={`min-h-screen ${isCrisisMode ? 'bg-[#120505]' : 'bg-[#0B0B0F]'} text-white flex overflow-hidden transition-colors duration-1000`}>
      {/* SIDEBAR */}
      <aside className="w-20 lg:w-72 bg-[#121217] border-r border-white/5 flex flex-col z-50">
        <div className="p-8 border-b border-white/5 flex items-center gap-4">
          <div className={`size-10 ${isCrisisMode ? 'bg-[#E10600] animate-pulse' : 'bg-[#E10600]'} rounded-sm flex items-center justify-center shadow-lg`}>
            {isCrisisMode ? <TriangleAlert size={20} /> : <Crown size={20} />}
          </div>
          <div className="hidden lg:block">
            <p className="font-black uppercase tracking-tighter text-lg leading-none">KRYPTON <span className="text-[#E10600]">CEO</span></p>
            <p className="text-[7px] font-black text-slate-500 uppercase tracking-widest mt-1">Super Admin Access</p>
          </div>
        </div>

        <nav className="flex-grow py-8 px-4 space-y-2 overflow-y-auto custom-scrollbar">
          {sidebarItems.map((item) => (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id as any)}
              className={`w-full flex items-center gap-6 p-4 rounded-sm transition-all group ${
                activeTab === item.id ? 'bg-[#E10600] text-white shadow-lg' : 'text-slate-500 hover:text-white hover:bg-white/5'
              } ${item.highlight && activeTab !== item.id ? 'border-r-2 border-[#E10600] animate-pulse' : ''}`}
            >
              <span className={`${activeTab === item.id ? 'text-white' : 'group-hover:text-[#E10600]'} transition-colors`}>
                {item.icon}
              </span>
              <span className="hidden lg:block text-[9px] font-black uppercase tracking-[0.2em] flex-grow text-left">
                {item.label}
              </span>
              {item.badge && item.badge !== '0' && (
                <span className={`hidden lg:flex size-5 ${activeTab === item.id ? 'bg-white text-black' : 'bg-[#E10600] text-white'} items-center justify-center rounded-full text-[8px] font-black shadow-lg`}>
                  {item.badge}
                </span>
              )}
            </button>
          ))}
        </nav>

        <div className="p-8 border-t border-white/5">
          <button onClick={onLogout} className="w-full flex items-center gap-6 p-4 text-[#E10600] hover:text-red-400 transition-all group">
            <LogOut size={18} />
            <span className="hidden lg:block text-[9px] font-black uppercase tracking-widest">Sortir du Cockpit</span>
          </button>
        </div>
      </aside>

      {/* MAIN CONTENT */}
      <main className="flex-grow flex flex-col overflow-hidden relative">
        <div className="absolute inset-0 hex-bg opacity-[0.03] pointer-events-none"></div>

        {/* TOPBAR */}
        <header className={`h-24 ${isCrisisMode ? 'bg-[#E10600]/10 border-[#E10600]/30' : 'bg-[#0B0B0F]/80 border-white/5'} backdrop-blur-md border-b px-10 flex items-center justify-between z-40 transition-colors duration-700`}>
           <div className="flex items-center gap-6">
              <div className={`px-4 py-2 ${isCrisisMode ? 'bg-[#E10600]/20 border-[#E10600]/50 text-[#E10600]' : 'bg-emerald-500/10 border border-emerald-500/30 text-emerald-500'} text-[8px] font-black uppercase tracking-widest rounded-full flex items-center gap-2`}>
                 <Activity size={12} className="animate-pulse" /> 
                 ÉTAT PLATEFORME : {isCrisisMode ? 'ALERTE CRITIQUE' : 'OPÉRATIONNEL'}
              </div>
              <div className="h-8 w-px bg-white/5"></div>
              <button 
                onClick={toggleCrisisMode}
                className={`px-6 py-2 border ${isCrisisMode ? 'bg-[#E10600] border-[#E10600] text-white' : 'border-white/10 text-slate-500 hover:text-white hover:border-[#E10600]'} text-[8px] font-black uppercase tracking-widest transition-all`}
              >
                {isCrisisMode ? 'MODE CRISE ACTIF' : 'ACTIVER CELLULE CRISE'}
              </button>
           </div>

           <div className="flex items-center gap-8">
              <div className="flex flex-col items-end">
                 <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest">SESSION_ACTIVE</p>
                 <p className="text-xs font-mono font-bold text-white uppercase tracking-tighter">{user?.firstName} (SUPER ADMIN)</p>
              </div>
              <div className="size-12 bg-[#1A1A1F] border border-white/10 rounded-full overflow-hidden flex items-center justify-center relative">
                 <User size={24} className="text-slate-600" />
                 <div className={`absolute bottom-0 right-0 size-3 ${isCrisisMode ? 'bg-yellow-500 animate-bounce' : 'bg-[#E10600]'} rounded-full border-2 border-[#0B0B0F]`}></div>
              </div>
           </div>
        </header>

        {/* CONTENT */}
        <div className="flex-grow overflow-y-auto p-10 custom-scrollbar relative z-10">
          <div className="max-w-7xl mx-auto space-y-12">

            {activeTab === 'overview' && (
              <>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                  {[
                    { label: 'C.A. GLOBAL', val: '142,5M FCFA', delta: '+22.4%', icon: <TrendingUp className="text-[#E10600]"/> },
                    { label: 'CONVERSION MOY.', val: '12.8%', delta: '+1.2%', icon: <BarChart3 className="text-[#E10600]"/> },
                    { label: 'PROJETS ACTIFS', val: '24', delta: 'Lancement imminent', icon: <Rocket className="text-[#E10600]"/> },
                    { label: 'ABANDONS PANIER', val: '4%', delta: '-2.1%', icon: <AlertTriangle className="text-yellow-500"/> },
                  ].map((stat, i) => (
                    <div key={i} className={`bg-[#1A1A1F] p-8 border border-white/5 relative group hover:border-[#E10600]/30 transition-all shadow-xl`}>
                      <div className="flex justify-between items-start mb-6">
                        <span className="text-[9px] font-black uppercase tracking-[0.2em] text-slate-600">{stat.label}</span>
                        {stat.icon}
