                           <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">RÉPARTITION DU C.A.</span>
                        </div>
                        <div className="space-y-6">
                           {[
                             { name: 'MARS', color: '#E10600', val: '45%', amount: '64.1M' },
                             { name: 'KRYPTON', color: '#3b82f6', val: '32%', amount: '45.6M' },
                             { name: 'TERRA', color: '#10b981', val: '18%', amount: '25.6M' },
