                               <div className="h-1 bg-white/5 w-full rounded-full overflow-hidden">
                                  <div className="h-full transition-all duration-1000" style={{ width: p.val, backgroundColor: p.color }}></div>
                               </div>
                             </div>
                           ))}
                        </div>
                     </div>
                  </div>

                  {/* CHAT FIKO */}
                  <div className={`bg-black border ${activeTab === 'optimization' ? 'border-emerald-500/50' : isCrisisMode ? 'border-[#E10600]' : 'border-white/10'} rounded-sm flex flex-col relative overflow-hidden shadow-2xl min-h-[500px]`}>
                     <div className="absolute inset-0 hex-bg opacity-10"></div>
                     <div className={`p-8 border-b ${isCrisisMode ? 'border-[#E10600]/30 bg-[#E10600]/10' : 'border-white/10 bg-white/5'} flex items-center gap-4 relative z-10`}>
                        <div className={`size-12 ${isCrisisMode ? 'bg-[#E10600] animate-pulse' : 'bg-[#E10600]/10 border border-[#E10600]/30'} rounded-full flex items-center justify-center shadow-lg`}>
                           {activeTab === 'optimization' ? <Sparkles className="text-emerald-500" size={24} /> : isCrisisMode ? <ShieldX className="text-white" size={24} /> : <Bot size={24} className="text-[#E10600]" />}
                        </div>
                        <div>
                           <p className={`text-sm font-black uppercase tracking-tighter ${isCrisisMode ? 'text-[#E10600]' : ''}`}>FIKO™ {activeTab === 'optimization' ? 'AUTO-OPT' : isCrisisMode ? 'CRISIS-CORE' : 'CEO-PILOT'}</p>
                           <p className="text-[8px] font-black text-slate-500 uppercase tracking-[0.4em]">{activeTab === 'optimization' ? 'APPRENTISSAGE CONTINU' : isCrisisMode ? 'PROTOCOL ALERTE ACTIF' : 'ASSISTANT EXÉCUTIF ACTIF'}</p>
                        </div>
                     </div>
                     <div ref={scrollRef} className="flex-grow overflow-y-auto p-8 space-y-6 custom-scrollbar relative z-10">
                       {messages.map((m, i) => (
                         <div key={i} className={`flex ${m.role === 'model' ? 'justify-start' : 'justify-end'}`}>
                           <div className={`max-w-[90%] p-6 rounded-sm text-[13px] shadow-xl border ${
                             m.role === 'model' 
                             ? (activeTab === 'optimization' ? 'bg-black border-emerald-500/30 text-emerald-100' : isCrisisMode ? 'bg-black border-[#E10600]/50 text-slate-100 italic' : 'bg-white/5 border-white/10 text-slate-300 italic') 
                             : 'bg-[#E10600] border-[#E10600] text-white font-bold uppercase tracking-widest'
                           }`}>
                             {m.text}
                           </div>
                         </div>
                       ))}
                     </div>
                     <div className="p-8 border-t border-white/10 relative z-10 bg-black">
                        <div className="relative">
                           <input 
                              value={input}
                              onChange={e => setInput(e.target.value)}
                              onKeyDown={e => e.key === 'Enter' && handleSend()}
