                </div>

                <div className="grid lg:grid-cols-2 gap-8">
                  {optimizations.map(opt => (
                    <div key={opt.id} className={`bg-[#1A1A1F] border ${opt.status === 'applied' ? 'border-emerald-500/50' : 'border-white/5'} p-10 rounded-sm space-y-8 relative overflow-hidden group transition-all`}>
                      {opt.status === 'applied' && <div className="absolute top-0 right-0 bg-emerald-500 text-black px-4 py-1 text-[8px] font-black uppercase tracking-widest">DÉPLOYÉ</div>}
                      <div className="flex justify-between items-start">
                        <div className="space-y-2">
                          <span className="text-[10px] font-black text-emerald-500 uppercase tracking-[0.4em]">{opt.category.toUpperCase()} // OPT-ENGINE</span>
                          <h4 className="text-2xl font-black uppercase tracking-tight">{opt.observation}</h4>
                        </div>
                        <Sparkles size={32} className={`${opt.status === 'applied' ? 'text-emerald-500' : 'text-slate-700'}`} />
                      </div>
                      <div className="space-y-4">
                        <div className="bg-black/40 p-6 border border-white/5">
                          <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-2">IMPACT ESTIMÉ :</p>
                          <p className="text-sm font-bold text-white uppercase tracking-widest">{opt.impact}</p>
                        </div>
                        <div className="p-6 bg-emerald-500/5 border border-emerald-500/20">
                          <p className="text-[9px] font-black text-emerald-500 uppercase tracking-widest mb-2">ACTION RECOMMANDÉE :</p>
                          <p className="text-sm font-medium italic text-emerald-100">{opt.action}</p>
                        </div>
                      </div>
                      <div className="flex justify-between items-center pt-4">
                        <div className="flex items-center gap-2">
                           <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest">RISQUE :</span>
                           <span className={`text-[9px] font-black uppercase tracking-widest ${opt.risk === 'low' ? 'text-emerald-500' : 'text-yellow-500'}`}>{opt.risk}</span>
                        </div>
                        {opt.status === 'pending' && (
                          <button 
                            onClick={() => applyOptimization(opt.id)}
                            className="bg-white text-black px-10 py-4 text-[9px] font-black uppercase tracking-widest hover:bg-emerald-500 hover:text-white transition-all shadow-xl"
                          >
                            AUTORISER L'APPLICATION
                          </button>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* SECTIONS PLACEHOLDERS */}
            {activeTab !== 'overview' && activeTab !== 'crisis' && activeTab !== 'optimization' && (
              <div className="bg-[#1A1A1F] border border-white/5 p-20 flex flex-col items-center justify-center text-center space-y-8 shadow-2xl rounded-sm">
                 <div className="size-24 bg-white/5 border border-white/10 rounded-sm flex items-center justify-center text-slate-500">
                    <Database size={44} />
                 </div>
                 <div className="space-y-4">
                    <h3 className="text-3xl font-black uppercase tracking-tighter">SECTION : {activeTab.toUpperCase()}</h3>
                    <p className="text-slate-500 uppercase text-[10px] font-bold tracking-[0.4em]">Chargement des données synchronisées Krypton-Cloud...</p>
                 </div>
                 <button onClick={() => setActiveTab('overview')} className="px-8 py-4 border border-[#E10600] text-[#E10600] text-[10px] font-black uppercase tracking-widest hover:bg-[#E10600] hover:text-white transition-all">RETOUR PILOTAGE</button>
              </div>
            )}
          </div>
        </div>
      </main>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: rgba(255,255,255,0.02); }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #E10600; }
      `}</style>
    </div>
  );
};

