import React, { useState, useEffect, useRef } from 'react';
import { Page, Message, UserProfile, UserRole, PlatformAlert, OptimizationSuggestion, AutonomousAction } from '../types';
import { FIKO_SUPER_ADMIN_PROMPT, FIKO_CRISIS_ALERT_PROMPT, FIKO_SEMI_AUTOPILOT_PROMPT } from '../constants';
import { GoogleGenAI } from '@google/genai';
import { 
  Hexagon, 
  Activity, 
  Clock, 
  ShieldCheck, 
  Settings,
  CreditCard,
  Rocket,
  Send,
  Bot,
  User,
  LogOut,
  LayoutDashboard,
  Users,
  Briefcase,
  TrendingUp,
  BarChart3,
  CheckCircle2,
  AlertTriangle,
  ArrowRight,
  Database,
  Globe,
  DoorOpen,
  ShieldAlert,
  BarChart,
  Crown,
  Zap,
  TriangleAlert,
