  Check
} from 'lucide-react';

interface AdminDashboardPageProps {
  onNavigate: (p: Page) => void;
  user: UserProfile | null;
  onLogout: () => void;
}

const AdminDashboardPage: React.FC<AdminDashboardPageProps> = ({ onNavigate, user, onLogout }) => {
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<'overview' | 'gates' | 'users' | 'projects' | 'agents' | 'payments' | 'analytics' | 'logs' | 'settings' | 'crisis' | 'autopilot'>('overview');
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [alerts, setAlerts] = useState<PlatformAlert[]>([]);
  const [optimizations, setOptimizations] = useState<OptimizationSuggestion[]>([]);
  const [autoActions, setAutoActions] = useState<AutonomousAction[]>([]);
  const [isCrisisMode, setIsCrisisMode] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const timer = setTimeout(() => {
      setLoading(false);
      setMessages([{
        role: 'model',
        text: `Mode Semi-Autopilot activé. J’optimise en continu à faible risque et je vous soumets toute décision critique. Quel est l'axe de supervision aujourd'hui ?`
      }]);

      // Simulation d'alertes, optimisations et actions autonomes
      setTimeout(() => {
        setAlerts([{
          id: 'ALRT-99',
          type: 'anomaly',
          severity: 'medium',
          title: 'BAISSE DE CONVERSION DÉTECTÉE',
          description: 'Le tunnel de la Porte MARS affiche une chute de 18% sur les dernières 2h.',
          timestamp: new Date().toLocaleTimeString(),
          impact: 'Perte estimée de 2.4M FCFA sur le flux quotidien.'
        }]);

        setOptimizations([
          {
            id: 'OPT-01',
            category: 'business',
            observation: 'Le panier moyen sur la Porte KRYPTON stagne malgré un trafic qualifié.',
            impact: 'Potentiel de CA additionnel de +4.2M FCFA/mois.',
            action: 'Ajuster le pricing vers une offre groupée incluant 3 mois de maintenance IA.',
            risk: 'medium',
            status: 'pending'
          }
        ]);

        setAutoActions([
          {
            id: 'ACT-01',
            timestamp: 'Il y a 12 min',
            category: 'UX',
            description: 'Modification du délai d’apparition du bouton FIKO™ de 5s à 12s.',
            impactObserved: 'Taux de rebond réduit de 4%.'
          },
          {
            id: 'ACT-02',
            timestamp: 'Il y a 45 min',
            category: 'Copy',
            description: 'Ajustement du CTA principal sur la Porte TERRA : "Démarrer" -> "Activer".',
            impactObserved: 'CTR +2.5%.'
          }
        ]);
      }, 3000);
    }, 2000);
    return () => clearTimeout(timer);
  }, []);

  useEffect(() => {
    scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
  }, [messages, isTyping]);

  const handleSend = async () => {
    if (!input.trim() || isTyping) return;
    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsTyping(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      let systemPrompt = FIKO_SUPER_ADMIN_PROMPT;
      if (isCrisisMode) systemPrompt = FIKO_CRISIS_ALERT_PROMPT;
      else if (activeTab === 'autopilot') systemPrompt = FIKO_SEMI_AUTOPILOT_PROMPT;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [...messages, { role: 'user', text: userMsg }].map(m => ({
          role: m.role,
          parts: [{ text: m.text }]
        })),
        config: {
          systemInstruction: systemPrompt,
          temperature: activeTab === 'autopilot' ? 0.3 : 0.5,
        }
      });
      setMessages(prev => [...prev, { role: 'model', text: response.text || "Système en attente." }]);
    } catch (e) {
      setMessages(prev => [...prev, { role: 'model', text: "Liaison saturée." }]);
    } finally {
      setIsTyping(false);
    }
  };

  const applyOptimization = (id: string) => {
    setOptimizations(prev => prev.map(o => o.id === id ? { ...o, status: 'applied' } : o));
    setMessages(prev => [...prev, { role: 'model', text: `Action stratégique validée. Déploiement en cours sur le noyau de production.` }]);
  };

  const toggleCrisisMode = () => {
    setIsCrisisMode(!isCrisisMode);
    if (!isCrisisMode) {
      setMessages(prev => [...prev, { role: 'model', text: "MODE CRISE ACTIVÉ. Protocoles de sécurité forcés." }]);
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-[#0B0B0F] flex flex-col items-center justify-center gap-8">
        <div className="relative">
           <Hexagon size={80} className="text-[#E10600] animate-[spin_4s_linear_infinite]" />
           <Crown size={24} className="absolute inset-0 m-auto text-white" />
        </div>
        <p className="text-[10px] font-black uppercase tracking-[0.6em] text-[#E10600] animate-pulse">Chargement du Cockpit CEO v9.4...</p>
      </div>
    );
