  };

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m}:${s < 10 ? '0' : ''}${s}`;
  };

  if (!agent) return null;

  return (
    <div className="fixed inset-0 z-[100] bg-black flex flex-col items-center justify-center animate-in fade-in duration-1000 p-6 overflow-hidden">
      <div className="absolute inset-0 hex-bg opacity-10"></div>

      <button onClick={onClose} className="absolute top-10 right-10 z-[110] group size-16 flex items-center justify-center bg-white/5 border border-white/10 rounded-full hover:bg-white hover:text-black transition-all">
        <X size={32} />
      </button>

      {/* FLOW INDICATOR */}
      <div className="absolute top-12 left-1/2 -translate-x-1/2 w-full max-w-4xl z-50 flex justify-between px-10">
        {[
          { id: FikoFlowStep.DISCOVERY, label: 'DIAGNOSTIC' },
          { id: FikoFlowStep.NEGOTIATION, label: 'NÉGOCIATION' },
          { id: FikoFlowStep.ACCOUNT_CREATION, label: 'COMPTE' },
          { id: FikoFlowStep.OFFER_CONFIRMATION, label: 'OFFRE' }
        ].map((s, i) => (
          <div key={i} className={`flex flex-col items-center gap-3 transition-opacity duration-500 ${flowStep === s.id ? 'opacity-100' : 'opacity-20'}`}>
            <div className={`size-8 rounded-full border-2 flex items-center justify-center text-[10px] font-black ${flowStep === s.id ? 'bg-[#E10600] border-[#E10600] shadow-[0_0_15px_#E10600]' : 'border-white/20'}`}>{i+1}</div>
            <span className="text-[8px] font-black tracking-[0.2em]">{s.label}</span>
          </div>
        ))}
      </div>

      {step === 'pre_start' && (
        <div className="text-center space-y-16 relative z-10">
          <Hexagon size={120} className="text-[#E10600] animate-[spin_10s_linear_infinite] mx-auto" strokeWidth={1} />
          <h2 className="text-6xl lg:text-[100px] font-black uppercase tracking-tighter text-white leading-none">
            FIKO <span className="text-[#E10600]">NEGOTIATOR.</span>
