function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

interface VocalSalesOverlayProps {
  agent: Agent | null;
  onClose: () => void;
  onOpenCheckout: (porte: string) => void;
  initialPorte?: string;
  initialFlowStep?: FikoFlowStep;
}

const VocalSalesOverlay: React.FC<VocalSalesOverlayProps> = ({ agent, onClose, onOpenCheckout, initialPorte, initialFlowStep }) => {
  const [step, setStep] = useState<'pre_start' | 'connecting' | 'active'>('pre_start');
  const [flowStep, setFlowStep] = useState<FikoFlowStep>(initialFlowStep || FikoFlowStep.DISCOVERY);
  const [isActive, setIsActive] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [bars, setBars] = useState<number[]>(new Array(40).fill(5));
  const [leadScore, setLeadScore] = useState(initialPorte ? 60 : 0);
  const [transcription, setTranscription] = useState("");
  const [discount, setDiscount] = useState<DiscountToken | null>(null);
  const [timeLeft, setTimeLeft] = useState<number>(0);
  const [emailInput, setEmailInput] = useState("");
  const [passwordInput, setPasswordInput] = useState("");
  const [selectedPorte, setSelectedPorte] = useState(initialPorte || "MARS");

  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const isClosingRef = useRef(false);

  useEffect(() => {
    let interval: number;
    if (discount && timeLeft > 0) {
      interval = window.setInterval(() => { setTimeLeft(t => t - 1); }, 1000);
    }
    return () => window.clearInterval(interval);
  }, [discount, timeLeft]);

  const stopSession = useCallback(() => {
    isClosingRef.current = true;
    setIsActive(false);
    sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
    sourcesRef.current.clear();
    if (inputAudioContextRef.current?.state !== 'closed') inputAudioContextRef.current?.close().catch(() => {});
    if (outputAudioContextRef.current?.state !== 'closed') outputAudioContextRef.current?.close().catch(() => {});
    if (sessionRef.current) try { sessionRef.current.close(); } catch(e) {}
    setBars(new Array(40).fill(5));
    isClosingRef.current = false;
  }, []);

  const startVocalSession = async () => {
    setStep('connecting');
    setError(null);
    try {
      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      if (inputCtx.state === 'suspended') await inputCtx.resume();
      if (outputCtx.state === 'suspended') await outputCtx.resume();
      inputAudioContextRef.current = inputCtx;
      outputAudioContextRef.current = outputCtx;
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setStep('active'); setIsActive(true);
            const source = inputCtx.createMediaStreamSource(stream);
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              if (!isActive) return;
              const inputData = e.inputBuffer.getChannelData(0);
              const volume = inputData.reduce((acc, v) => acc + Math.abs(v), 0) / inputData.length;
              setBars(prev => prev.map(() => Math.floor(Math.random() * (volume * 800 + 5)) + 5));
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              const pcmBlob = { data: encode(new Uint8Array(int16.buffer)), mimeType: 'audio/pcm;rate=16000' };
              sessionPromise.then(s => s.sendRealtimeInput({ media: pcmBlob }));
            };
            source.connect(scriptProcessor); scriptProcessor.connect(inputCtx.destination);
            const intro = initialPorte ? `Porte ${initialPorte} choisie. Applique protocole NÉGOCIATEUR si besoin.` : `Diagnostic stratégique d'abord.`;
            sessionPromise.then(s => s.sendRealtimeInput([{ text: intro }]));
          },
          onmessage: async (m: LiveServerMessage) => {
            if (m.serverContent?.inputTranscription) setTranscription(m.serverContent.inputTranscription.text);
            const base64 = m.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64 && outputCtx.state !== 'closed') {
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputCtx.currentTime);
              const buffer = await decodeAudioData(decode(base64), outputCtx, 24000, 1);
              const source = outputCtx.createBufferSource(); source.buffer = buffer; source.connect(outputCtx.destination);
              source.onended = () => { sourcesRef.current.delete(source); if (sourcesRef.current.size === 0) setBars(new Array(40).fill(5)); };
              source.start(nextStartTimeRef.current); nextStartTimeRef.current += buffer.duration; sourcesRef.current.add(source);
              setLeadScore(prev => Math.min(prev + 4, 100));
            }
          },
          onerror: () => { setError("LIAISON INTERROMPUE."); stopSession(); }
        },
        config: {
          responseModalities: [Modality.AUDIO], inputAudioTranscription: {},
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } } },
          systemInstruction: FIKO_NEGOTIATOR_PROMPT + (agent?.systemPrompt || "")
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (e) { setError("ACCÈS MICRO REFUSÉ."); setStep('pre_start'); }
  };

  const triggerNegotiation = () => {
    setFlowStep(FikoFlowStep.NEGOTIATION);
    setDiscount({ id: 'D1', code: 'KRYPTON24H-10', offer: selectedPorte, percent: 10, expiresAt: '', intentScore: 88, status: 'active' });
    setTimeLeft(3600);
    sessionRef.current?.sendRealtimeInput([{ text: "Accorde 10% valable 24h." }]);
  };

  const formatTime = (seconds: number) => `${Math.floor(seconds / 60)}:${(seconds % 60).toString().padStart(2, '0')}`;

  if (!agent) return null;

  return (
    <div className="fixed inset-0 z-[100] bg-black flex flex-col items-center justify-center p-6 overflow-hidden animate-in fade-in duration-700">
      <div className="absolute inset-0 hex-bg opacity-10"></div>
      <button onClick={onClose} className="absolute top-10 right-10 z-[110] size-16 flex items-center justify-center bg-white/5 border border-white/10 rounded-full hover:bg-white hover:text-black transition-all"><X size={32} /></button>

      {/* FLOW INDICATOR */}
      <div className="absolute top-12 left-1/2 -translate-x-1/2 w-full max-w-4xl z-50 flex justify-between px-10">
        {[{ id: FikoFlowStep.DISCOVERY, label: 'DIAGNOSTIC' }, { id: FikoFlowStep.NEGOTIATION, label: 'NÉGOCIATION' }, { id: FikoFlowStep.ACCOUNT_CREATION, label: 'COMPTE' }, { id: FikoFlowStep.OFFER_CONFIRMATION, label: 'OFFRE' }].map((s, i) => (
          <div key={i} className={`flex flex-col items-center gap-3 transition-all duration-500 ${flowStep === s.id ? 'opacity-100' : 'opacity-20'}`}>
            <div className={`size-8 rounded-full border-2 flex items-center justify-center text-[10px] font-black ${flowStep === s.id ? 'bg-[#E10600] border-[#E10600] shadow-[0_0_15px_#E10600]' : 'border-white/20'}`}>{i+1}</div>
            <span className="text-[8px] font-black tracking-[0.2em]">{s.label}</span>
          </div>
        ))}
      </div>

      {step === 'pre_start' && (
        <div className="text-center space-y-16 relative z-10">
          <Hexagon size={120} className="text-[#E10600] animate-[spin_10s_linear_infinite] mx-auto" strokeWidth={1} />
          <h2 className="text-6xl lg:text-[100px] font-black uppercase tracking-tighter text-white leading-none">FIKO <span className="text-[#E10600]">NEGOTIATOR.</span></h2>
          <button onClick={startVocalSession} className="bg-[#E10600] text-white px-16 py-8 font-black text-xs uppercase tracking-[0.5em] shadow-2xl flex items-center gap-6 mx-auto hover:scale-105 active:scale-95 transition-all">🎙️ INITIALISER CLOSING</button>
        </div>
      )}

      {step === 'active' && (
        <div className="flex flex-col items-center justify-center h-full w-full max-w-5xl relative">
           <div className="relative z-10 flex items-center justify-center gap-2 h-48 w-full">
             {bars.map((h, i) => <div key={i} className="w-2 md:w-3 rounded-full bg-[#E10600] transition-all duration-150" style={{ height: `${h}%`, opacity: (h / 100) * 0.5 + 0.5 }}></div>)}
           </div>

           {discount && (
              <div className="mt-10 bg-white p-8 rounded-sm shadow-[0_0_80px_rgba(255,255,255,0.2)] animate-in slide-in-from-top-12 border-t-8 border-[#E10600] w-full max-w-md">
                <div className="flex justify-between items-center mb-6">
                   <div className="flex items-center gap-3 text-black"><Timer className="animate-pulse" size={20} /><span className="text-2xl font-mono font-black">{formatTime(timeLeft)}</span></div>
                   <div className="bg-[#E10600] text-white px-4 py-2 text-[10px] font-black uppercase tracking-widest">FIKO™ TOKEN</div>
                </div>
                <h4 className="text-black text-3xl font-black uppercase tracking-tighter mb-4">REMISE DE {discount.percent}% ACTIVÉE</h4>
                <p className="text-slate-600 font-bold text-xs uppercase tracking-widest leading-relaxed">VALABLE SUR LA PORTE {discount.offer} POUR UN CLOSING SOUS 24H.</p>
              </div>
           )}

           <div className="mt-16 text-center space-y-12 relative z-20 w-full max-w-lg">
              {flowStep === FikoFlowStep.DISCOVERY && (
                 <div className="space-y-6">
                    <p className="text-xl text-slate-400 font-light italic leading-relaxed">"Score d'intention détecté : {leadScore}/100"</p>
                    {leadScore > 75 && !discount && <button onClick={triggerNegotiation} className="bg-white/10 text-white px-8 py-4 text-[10px] font-black uppercase tracking-widest hover:bg-white hover:text-black transition-all flex items-center gap-4 mx-auto animate-pulse"><Sparkles size={16} /> ACCÉDER NÉGOCIATION</button>}
                 </div>
              )}
              {flowStep === FikoFlowStep.NEGOTIATION && <button onClick={() => setFlowStep(FikoFlowStep.ACCOUNT_CREATION)} className="bg-[#E10600] text-white px-12 py-6 text-[10px] font-black uppercase tracking-[0.3em] hover:scale-105 transition-all shadow-xl shadow-red-500/30">VERROUILLER CETTE REMISE</button>}
              {flowStep === FikoFlowStep.ACCOUNT_CREATION && (
                <div className="bg-[#1A1A1F] border border-white/10 p-10 rounded-sm space-y-6 text-left">
                  <div className="flex items-center gap-3 text-[#E10600] mb-4"><UserPlus size={20} /><span className="text-[10px] font-black uppercase tracking-widest">CRÉATION COMPTE PARTENAIRE</span></div>
                  <input type="email" placeholder="EMAIL PROFESSIONNEL" value={emailInput} onChange={e => setEmailInput(e.target.value)} className="w-full bg-black border border-white/10 p-5 text-white text-[10px] font-black uppercase tracking-widest outline-none focus:border-[#E10600]" />
                  <input type="password" placeholder="CODE SÉCURITÉ (4 CHIFFRES)" value={passwordInput} onChange={e => setPasswordInput(e.target.value.replace(/\D/g,''))} className="w-full bg-black border border-white/10 p-5 text-white text-[10px] font-black uppercase tracking-widest outline-none focus:border-[#E10600]" />
                  <button onClick={() => setFlowStep(FikoFlowStep.OFFER_CONFIRMATION)} className="w-full bg-[#E10600] py-6 text-white font-black text-[10px] uppercase tracking-widest">FINALISER LE COMPTE</button>
                </div>
              )}
              {flowStep === FikoFlowStep.OFFER_CONFIRMATION && (
                <div className="bg-white p-12 rounded-sm text-black space-y-8 shadow-2xl">
                  <div className="flex justify-between items-center mb-4"><h4 className="font-black text-[11px] uppercase tracking-widest opacity-60">CONTRAT NEURAL FIKO™</h4><Tag className="text-[#E10600]" size={20} /></div>
                  <div className="space-y-4"><p className="text-4xl font-black uppercase tracking-tighter leading-none">PORTE {selectedPorte}</p>{discount && <p className="text-xl font-black text-[#E10600] uppercase tracking-widest">- {discount.percent}% APPLIQUÉ</p>}</div>
                  <button onClick={() => onOpenCheckout(selectedPorte)} className="w-full bg-black text-white py-8 font-black text-xs uppercase tracking-[0.4em] hover:scale-105 transition-transform flex items-center justify-center gap-6">COMMANDER MAINTENANT <ArrowRight size={24} /></button>
                </div>
              )}
              {transcription && <div className="max-w-2xl mx-auto bg-white/5 border border-white/10 p-6 text-white text-lg italic leading-relaxed rounded-sm backdrop-blur-md animate-in fade-in duration-500">"{transcription}"</div>}
           </div>
