              </div>
           )}

           <div className="mt-16 text-center space-y-12 relative z-20 w-full max-w-lg">
              {flowStep === FikoFlowStep.DISCOVERY && (
                 <div className="space-y-6">
                    <p className="text-xl text-slate-400 font-light italic leading-relaxed">"FIKO™ analyse votre score d'intention stratégique : {leadScore}/100"</p>
