              {flowStep === FikoFlowStep.NEGOTIATION && (
                <button onClick={() => setFlowStep(FikoFlowStep.ACCOUNT_CREATION)} className="bg-[#E10600] text-white px-12 py-6 text-[10px] font-black uppercase tracking-[0.3em] hover:scale-105 transition-all shadow-xl shadow-red-500/30 group">
                   VERROUILLER CETTE REMISE & CRÉER MON COMPTE <ArrowRight size={16} className="inline ml-4 group-hover:translate-x-2 transition-transform" />
                </button>
              )}
              {flowStep === FikoFlowStep.ACCOUNT_CREATION && (
                <div className="bg-[#1A1A1F] border border-white/10 p-10 rounded-sm space-y-6 text-left animate-in fade-in zoom-in-95">
                  <div className="flex items-center gap-3 text-[#E10600] mb-4"><UserPlus size={20} /><span className="text-[10px] font-black uppercase tracking-widest">ENREGISTREMENT PARTENAIRE KRYPTON</span></div>
                  <div className="space-y-4">
                    <input type="email" placeholder="EMAIL PROFESSIONNEL" value={emailInput} onChange={e => setEmailInput(e.target.value)} className="w-full bg-black border border-white/10 p-5 text-white text-[10px] font-black uppercase tracking-widest outline-none focus:border-[#E10600] transition-all" />
                    <input type="password" placeholder="CODE SÉCURITÉ (4 CHIFFRES)" value={passwordInput} onChange={e => setPasswordInput(e.target.value.replace(/\D/g,''))} className="w-full bg-black border border-white/10 p-5 text-white text-[10px] font-black uppercase tracking-widest outline-none focus:border-[#E10600] transition-all" />
