    if (leadScore >= DISCOUNT_RULES.INTENT_THRESHOLD && flowStep === FikoFlowStep.DISCOVERY && !discount) {
      // Logic: Propose the best discount (10% for 24h) if score is very high (85+), 
      // otherwise propose 5% for 72h.
