  initialFlowStep?: FikoFlowStep;
}

const VocalSalesOverlay: React.FC<VocalSalesOverlayProps> = ({ agent, onClose, onOpenCheckout, initialPorte, initialFlowStep }) => {
  const [step, setStep] = useState<'pre_start' | 'connecting' | 'active'>('pre_start');
  const [flowStep, setFlowStep] = useState<FikoFlowStep>(initialFlowStep || FikoFlowStep.DISCOVERY);
  const [isActive, setIsActive] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [bars, setBars] = useState<number[]>(new Array(40).fill(5));
  const [leadScore, setLeadScore] = useState(initialPorte ? 60 : 0);
  const [transcription, setTranscription] = useState("");
  const [discount, setDiscount] = useState<DiscountToken | null>(null);
  const [timeLeft, setTimeLeft] = useState<number>(0);
  const [emailInput, setEmailInput] = useState("");
  const [passwordInput, setPasswordInput] = useState("");
  const [selectedPorte, setSelectedPorte] = useState(initialPorte || "MARS");

  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const isClosingRef = useRef(false);

  useEffect(() => {
    let interval: number;
    if (discount && timeLeft > 0) {
      interval = window.setInterval(() => { setTimeLeft(t => t - 1); }, 1000);
    }
    return () => window.clearInterval(interval);
  }, [discount, timeLeft]);

  // Autopilot logic: Auto-trigger negotiation tiers based on engagement depth
  useEffect(() => {
    if (leadScore >= DISCOUNT_RULES.INTENT_THRESHOLD && flowStep === FikoFlowStep.DISCOVERY && !discount) {
      // Logic: Propose the best discount (10% for 24h) if score is very high (85+), 
      // otherwise propose 5% for 72h.
      const tierIndex = leadScore >= 85 ? 0 : 1; 
      setTimeout(() => triggerNegotiation(tierIndex), 2000);
    }
  }, [leadScore, flowStep, discount]);

  const stopSession = useCallback(() => {
    isClosingRef.current = true;
    setIsActive(false);
    sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
    sourcesRef.current.clear();
    if (inputAudioContextRef.current?.state !== 'closed') inputAudioContextRef.current?.close().catch(() => {});
    if (outputAudioContextRef.current?.state !== 'closed') outputAudioContextRef.current?.close().catch(() => {});
    if (sessionRef.current) try { sessionRef.current.close(); } catch(e) {}
    setBars(new Array(40).fill(5));
    isClosingRef.current = false;
  }, []);

  const startVocalSession = async () => {
    setStep('connecting');
    setError(null);
    try {
      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      if (inputCtx.state === 'suspended') await inputCtx.resume();
      if (outputCtx.state === 'suspended') await outputCtx.resume();
      inputAudioContextRef.current = inputCtx;
      outputAudioContextRef.current = outputCtx;
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setStep('active'); setIsActive(true);
            const source = inputCtx.createMediaStreamSource(stream);
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              if (!isActive) return;
              const inputData = e.inputBuffer.getChannelData(0);
              const volume = inputData.reduce((acc, v) => acc + Math.abs(v), 0) / inputData.length;
              setBars(prev => prev.map(() => Math.floor(Math.random() * (volume * 800 + 5)) + 5));
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              const pcmBlob = { data: encode(new Uint8Array(int16.buffer)), mimeType: 'audio/pcm;rate=16000' };
              sessionPromise.then(s => s.sendRealtimeInput({ media: pcmBlob }));
            };
            source.connect(scriptProcessor); scriptProcessor.connect(inputCtx.destination);
            const intro = initialPorte ? `Porte ${initialPorte} choisie. Diagnostic stratégique lancé. Je détecte votre niveau d'engagement.` : `Diagnostic stratégique d'abord. Présentez-moi votre projet.`;
            sessionPromise.then(s => s.sendRealtimeInput([{ text: intro }]));
          },
          onmessage: async (m: LiveServerMessage) => {
            if (m.serverContent?.inputTranscription) setTranscription(m.serverContent.inputTranscription.text);
            const base64 = m.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64 && outputCtx.state !== 'closed') {
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputCtx.currentTime);
              const buffer = await decodeAudioData(decode(base64), outputCtx, 24000, 1);
              const source = outputCtx.createBufferSource(); source.buffer = buffer; source.connect(outputCtx.destination);
              source.onended = () => { sourcesRef.current.delete(source); if (sourcesRef.current.size === 0) setBars(new Array(40).fill(5)); };
              source.start(nextStartTimeRef.current); nextStartTimeRef.current += buffer.duration; sourcesRef.current.add(source);
              // Lead score increases with interaction depth
              setLeadScore(prev => Math.min(prev + (flowStep === FikoFlowStep.DISCOVERY ? 6 : 1), 100));
            }
          },
          onerror: () => { setError("LIAISON NEURALE INTERROMPUE."); stopSession(); }
        },
        config: {
          responseModalities: [Modality.AUDIO], inputAudioTranscription: {},
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } } },
          systemInstruction: FIKO_NEGOTIATOR_PROMPT + `\nLe client est intéressé par la PORTE ${selectedPorte}. Applique les paliers de remise uniquement sur preuve d'engagement.`
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (e) { setError("ACCÈS MICRO REFUSÉ PAR LE SYSTÈME."); setStep('pre_start'); }
  };

  const triggerNegotiation = (tierIndex: number = 0) => {
    const tier = DISCOUNT_RULES.TIERS[tierIndex];
    setFlowStep(FikoFlowStep.NEGOTIATION);
    const token = `KRYPTON-${tier.percent}PCT-${Math.random().toString(36).substr(2, 4).toUpperCase()}`;
    setDiscount({ 
        id: 'D' + Date.now(), 
        code: token, 
        offer: selectedPorte, 
        percent: tier.percent, 
        expiresAt: '', 
        intentScore: leadScore, 
        status: 'active' 
    });
    setTimeLeft(3600); // UI display: 1h for the *session* to lock the token, though the rule is 24h/72h/7d
    sessionRef.current?.sendRealtimeInput([{ 
        text: `ACTION SYSTÈME : Engagement détecté. Application de la remise tierce ${tier.label} (${tier.percent}%). Explique au client qu'il s'agit d'une opportunité unique verrouillée par le token ${token}.` 
    }]);
  };

  const handleAccountComplete = () => {
    setFlowStep(FikoFlowStep.OFFER_CONFIRMATION);
    sessionRef.current?.sendRealtimeInput([{ text: "ACTION SYSTÈME : Compte sécurisé. Le partenariat est désormais scellé. Invite au paiement final avec la remise appliquée." }]);
  };

  const formatTime = (seconds: number) => `${Math.floor(seconds / 60)}:${(seconds % 60).toString().padStart(2, '0')}`;

  if (!agent) return null;

  return (
    <div className="fixed inset-0 z-[100] bg-black flex flex-col items-center justify-center p-6 overflow-hidden animate-in fade-in duration-700">
      <div className="absolute inset-0 hex-bg opacity-10"></div>
      <button onClick={onClose} className="absolute top-10 right-10 z-[110] size-16 flex items-center justify-center bg-white/5 border border-white/10 rounded-full hover:bg-white hover:text-black transition-all group">
        <X size={32} className="group-hover:rotate-90 transition-transform" />
      </button>

      {/* FLOW INDICATOR */}
      <div className="absolute top-12 left-1/2 -translate-x-1/2 w-full max-w-4xl z-50 flex justify-between px-10">
        {[
          { id: FikoFlowStep.DISCOVERY, label: 'DIAGNOSTIC' }, 
          { id: FikoFlowStep.NEGOTIATION, label: 'NÉGOCIATION' }, 
          { id: FikoFlowStep.ACCOUNT_CREATION, label: 'COMPTE' }, 
          { id: FikoFlowStep.OFFER_CONFIRMATION, label: 'OFFRE' }
        ].map((s, i) => (
          <div key={i} className={`flex flex-col items-center gap-3 transition-all duration-500 ${flowStep === s.id ? 'opacity-100' : 'opacity-20'}`}>
            <div className={`size-8 rounded-full border-2 flex items-center justify-center text-[10px] font-black ${flowStep === s.id ? 'bg-[#E10600] border-[#E10600] shadow-[0_0_15px_#E10600]' : 'border-white/20'}`}>{i+1}</div>
            <span className="text-[8px] font-black tracking-[0.2em]">{s.label}</span>
          </div>
        ))}
      </div>

      {step === 'pre_start' && (
        <div className="text-center space-y-16 relative z-10 animate-in slide-in-from-bottom-8">
          <Hexagon size={120} className="text-[#E10600] animate-[spin_10s_linear_infinite] mx-auto" strokeWidth={1} />
          <h2 className="text-6xl lg:text-[100px] font-black uppercase tracking-tighter text-white leading-none">FIKO <span className="text-[#E10600]">NEGOTIATOR.</span></h2>
          <button onClick={startVocalSession} className="bg-[#E10600] text-white px-16 py-8 font-black text-xs uppercase tracking-[0.5em] shadow-2xl flex items-center gap-6 mx-auto hover:scale-105 active:scale-95 transition-all">🎙️ INITIALISER LE CLOSING</button>
        </div>
      )}

      {step === 'active' && (
        <div className="flex flex-col items-center justify-center h-full w-full max-w-5xl relative">
           <div className="relative z-10 flex items-center justify-center gap-2 h-48 w-full mb-10">
             {bars.map((h, i) => <div key={i} className="w-2 md:w-3 rounded-full bg-[#E10600] transition-all duration-150" style={{ height: `${h}%`, opacity: (h / 100) * 0.5 + 0.5 }}></div>)}
           </div>

           {/* DYNAMIC NEGOTIATION CARD */}
           {discount && (
              <div className="bg-white p-10 rounded-sm shadow-[0_0_120px_rgba(255,255,255,0.2)] animate-in slide-in-from-top-12 border-t-8 border-[#E10600] w-full max-w-md relative group/card">
                <div className="absolute -top-14 left-1/2 -translate-x-1/2 flex items-center gap-4 bg-black border border-white/10 px-8 py-3 rounded-full shadow-2xl">
                   <Timer className="animate-pulse text-[#E10600]" size={20} />
                   <span className="text-2xl font-mono font-black text-white">{formatTime(timeLeft)}</span>
                </div>
                <div className="flex justify-between items-center mb-6">
                   <div className="bg-[#E10600] text-white px-5 py-2 text-[10px] font-black uppercase tracking-widest flex items-center gap-3">
                      <Zap size={14} fill="white" /> OFFRE EXCLUSIVE FIKO™
                   </div>
                   <ShieldCheck className="text-[#E10600]" size={24} />
                </div>
                <h4 className="text-black text-4xl font-black uppercase tracking-tighter mb-4 leading-none">REMISE DE {discount.percent}% ACTIVÉE</h4>
                <p className="text-slate-600 font-bold text-sm uppercase tracking-widest leading-relaxed mb-6">
                   VOTRE ENGAGEMENT A DÉBLOQUÉ LE TARIF PRÉFÉRENTIEL SUR LA PORTE {discount.offer}.
                </p>
                <div className="flex items-center justify-between mt-8 pt-6 border-t border-slate-100">
                   <div className="space-y-1">
                      <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">ID_TOKEN_VERROUILLE</p>
                      <p className="font-mono text-xs text-black font-black">{discount.code}</p>
                   </div>
                   <Tag className="text-[#E10600]" size={20} />
                </div>
              </div>
           )}

           <div className="mt-16 text-center space-y-12 relative z-20 w-full max-w-lg">
              {flowStep === FikoFlowStep.DISCOVERY && (
                 <div className="space-y-8 animate-in fade-in duration-1000">
                    <div className="space-y-2">
                       <p className="text-xl text-slate-400 font-light italic leading-relaxed">"FIKO™ évalue votre potentiel de croissance : {leadScore}/100"</p>
                       <div className="w-full h-1 bg-white/5 rounded-full overflow-hidden max-w-xs mx-auto">
                          <div className="h-full bg-[#E10600] transition-all duration-1000 shadow-[0_0_10px_#E10600]" style={{ width: `${leadScore}%` }}></div>
                       </div>
                    </div>
                    {leadScore >= 60 && !discount && (
                       <p className="text-[10px] font-black uppercase tracking-[0.4em] text-[#E10600] animate-pulse">Synchronisation des opportunités en cours...</p>
                    )}
                 </div>
              )}

              {flowStep === FikoFlowStep.NEGOTIATION && (
                <div className="space-y-8 animate-in slide-in-from-bottom-4">
                   <button onClick={() => setFlowStep(FikoFlowStep.ACCOUNT_CREATION)} className="bg-[#E10600] text-white px-14 py-8 text-[11px] font-black uppercase tracking-[0.4em] hover:scale-105 transition-all shadow-2xl shadow-red-500/30 group">
                      SÉCURISER CETTE OFFRE <ArrowRight size={20} className="inline ml-4 group-hover:translate-x-3 transition-transform" />
                   </button>
                   <p className="text-[10px] font-black text-slate-600 uppercase tracking-widest italic">
                      En cliquant, vous confirmez votre intention de closing sous le délai imparti.
                   </p>
                </div>
              )}

              {flowStep === FikoFlowStep.ACCOUNT_CREATION && (
                <div className="bg-[#1A1A1F] border border-white/10 p-12 rounded-sm space-y-8 text-left animate-in fade-in zoom-in-95 shadow-2xl">
                  <div className="flex items-center gap-4 text-[#E10600] mb-4">
                     <UserPlus size={24} /> <span className="text-sm font-black uppercase tracking-[0.2em]">IDENTITÉ DU PARTENAIRE</span>
                  </div>
                  <div className="space-y-4">
                    <div className="relative group">
                       <Mail className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-700" size={18} />
                       <input type="email" placeholder="EMAIL PROFESSIONNEL" value={emailInput} onChange={e => setEmailInput(e.target.value)} className="w-full bg-black border border-white/10 p-6 pl-16 text-white text-xs font-black uppercase tracking-widest outline-none focus:border-[#E10600] transition-all" />
                    </div>
                    <div className="relative group">
                       <Lock className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-700" size={18} />
                       <input type="password" placeholder="CODE SÉCURITÉ (4 CHIFFRES)" value={passwordInput} onChange={e => setPasswordInput(e.target.value.replace(/\D/g,''))} className="w-full bg-black border border-white/10 p-6 pl-16 text-white text-xs font-black uppercase tracking-widest outline-none focus:border-[#E10600] transition-all" />
                    </div>
                  </div>
                  <button onClick={handleAccountComplete} className="w-full bg-[#E10600] py-8 text-white font-black text-xs uppercase tracking-[0.4em] shadow-xl shadow-red-500/20 active:scale-95 transition-all">ENREGISTRER MES PRIVILÈGES</button>
                </div>
              )}

              {flowStep === FikoFlowStep.OFFER_CONFIRMATION && (
                <div className="bg-white p-14 rounded-sm text-black space-y-12 shadow-[0_40px_100px_rgba(0,0,0,0.5)] animate-in slide-in-from-bottom-8 relative overflow-hidden">
                  <div className="absolute top-0 right-0 p-8 opacity-[0.05] pointer-events-none">
                     <ShieldCheck size={120} />
                  </div>
                  <div className="flex justify-between items-center border-b border-slate-100 pb-8">
                    <div>
                       <h4 className="font-black text-[11px] uppercase tracking-[0.5em] opacity-40 mb-2">CONTRAT NEURAL FIKO™ v9.4</h4>
                       <p className="text-xs font-bold uppercase tracking-widest">PARTENARIAT STRATÉGIQUE</p>
                    </div>
                    <Tag className="text-[#E10600]" size={28} />
                  </div>
                  <div className="space-y-8">
                    <div className="space-y-2">
                       <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">CONFIGURATION FINALE</p>
                       <p className="text-6xl font-black uppercase tracking-tighter leading-none">PORTE {selectedPorte}</p>
                    </div>
                    {discount && (
                      <div className="bg-emerald-500/10 border border-emerald-500/20 px-8 py-6 flex justify-between items-center rounded-sm">
                        <div className="flex items-center gap-4">
                           <Clock className="text-emerald-600" size={20} />
                           <span className="text-[10px] font-black text-emerald-600 uppercase tracking-[0.2em]">REMISE TEMPORELLE ACTIVÉE</span>
                        </div>
                        <span className="text-3xl font-black text-emerald-600">-{discount.percent}%</span>
                      </div>
                    )}
                  </div>
                  <button onClick={() => onOpenCheckout(selectedPorte)} className="w-full bg-black text-white py-12 font-black text-sm uppercase tracking-[0.6em] hover:scale-105 active:scale-95 transition-transform flex items-center justify-center gap-8 shadow-2xl">
                    PROCÉDER AU PAIEMENT <ArrowRight size={32} />
                  </button>
                </div>
              )}

              {transcription && (
                <div className="max-w-2xl mx-auto bg-black/60 border border-white/5 p-8 text-white text-xl italic leading-relaxed rounded-sm backdrop-blur-md animate-in fade-in duration-500 shadow-2xl border-l-4 border-[#E10600]">
                   "{transcription}"
                </div>
              )}
           </div>
        </div>
      )}

      {error && (
        <div className="fixed bottom-12 left-1/2 -translate-x-1/2 z-[150] bg-[#E10600] border border-white/20 p-10 rounded-sm flex items-center gap-10 shadow-2xl animate-in slide-in-from-bottom-4 max-w-2xl">
           <AlertTriangle className="text-white" size={48} />
           <div className="space-y-4">
              <p className="text-base font-black uppercase tracking-widest text-white leading-relaxed">{error}</p>
              <button onClick={() => { setError(null); startVocalSession(); }} className="flex items-center gap-4 px-6 py-3 bg-white/10 rounded-full hover:bg-white/20 transition-all text-[10px] font-black uppercase tracking-widest text-white">
                 <RefreshCcw size={18} /> RÉINITIALISER LA LIAISON
              </button>
           </div>
        </div>
      )}
    </div>
  );
};

export default VocalSalesOverlay;

import React, { useState, useEffect, useRef } from 'react';
import { Page, Message, UserProfile, UserRole, PlatformAlert, OptimizationSuggestion, AutonomousAction, DiscountToken } from '../types';
import { FIKO_SUPER_ADMIN_PROMPT, FIKO_CRISIS_ALERT_PROMPT, FIKO_SEMI_AUTOPILOT_PROMPT, DISCOUNT_RULES } from '../constants';
import { GoogleGenAI } from '@google/genai';
import { 
  Hexagon, Activity, Clock, ShieldCheck, Settings, CreditCard, Rocket, Send, Bot, User, LogOut, LayoutDashboard,
  Users, Briefcase, TrendingUp, BarChart3, CheckCircle2, AlertTriangle, ArrowRight, Database, Globe, DoorOpen,
  ShieldAlert, BarChart, Crown, Zap, TriangleAlert, ShieldX, Sparkles, RefreshCw, Cpu, History, Check, Tag, Timer, Ban
} from 'lucide-react';

interface AdminDashboardPageProps {
  onNavigate: (p: Page) => void;
  user: UserProfile | null;
  onLogout: () => void;
}

const AdminDashboardPage: React.FC<AdminDashboardPageProps> = ({ onNavigate, user, onLogout }) => {
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<'overview' | 'negotiation' | 'autopilot' | 'gates' | 'users' | 'analytics' | 'settings' | 'crisis'>('overview');
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [alerts, setAlerts] = useState<PlatformAlert[]>([]);
  const [optimizations, setOptimizations] = useState<OptimizationSuggestion[]>([]);
  const [autoActions, setAutoActions] = useState<AutonomousAction[]>([]);
  const [discountTokens, setDiscountTokens] = useState<DiscountToken[]>([]);
  const [isCrisisMode, setIsCrisisMode] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const timer = setTimeout(() => {
      setLoading(false);
      setMessages([{
        role: 'model',
        text: `Mode Semi-Autopilot v9.4 opérationnel. Je surveille les flux de négociation et les performances des agents. Prêt pour l'analyse stratégique.`
      }]);

      setDiscountTokens([
        { id: '1', code: 'MARS-72H-5', percent: 5, offer: 'MARS', expiresAt: '2026-02-10 14:00', intentScore: 82, status: 'active' },
        { id: '2', code: 'KRYPTON-24H-10', percent: 10, offer: 'KRYPTON', expiresAt: '2026-02-09 18:00', intentScore: 94, status: 'active' },
        { id: '3', code: 'TERRA-7D-3', percent: 3, offer: 'TERRA', expiresAt: 'Expiré', intentScore: 76, status: 'expired' }
      ]);

      setOptimizations([
        {
          id: 'OPT-01',
          category: 'business',
          observation: 'Baisse de 14% de conversion sur la Porte MARS après 22h.',
          impact: 'Gain CA estimé : +3.2M FCFA/mois via activation IA de nuit.',
          action: 'Basculer l’agent FIKO™ en mode "Directeur de Nuit" (Urgence élevée).',
          risk: 'medium',
          status: 'pending'
        },
        {
          id: 'OPT-02',
          category: 'performance',
          observation: 'Trafic intense détecté sur le tunnel KRYPTON.',
          impact: 'Risque de saturation des serveurs d\'inférence.',
          action: 'Déployer 4 nœuds additionnels sur le cluster Europe-West.',
          risk: 'low',
          status: 'pending'
        }
      ]);

      setAutoActions([
        { id: 'ACT-01', timestamp: 'Il y a 14 min', category: 'UX', description: 'Réduction délai FIKO (5s -> 3s) sur mobile.', impactObserved: 'Engagement +8%' },
        { id: 'ACT-02', timestamp: 'Il y a 2h', category: 'Copy', description: 'Ajustement CTA "Accéder" -> "Activer".', impactObserved: 'CTR +4.5%' },
        { id: 'ACT-03', timestamp: 'Il y a 4h', category: 'Nego', description: 'Activation relance douce sur 3 paniers abandonnés.', impactObserved: '1 Closing (2M FCFA)' }
      ]);

      setAlerts([{
        id: 'ALRT-99',
        type: 'anomaly',
        severity: 'medium',
        title: 'LATENCE NEURALE DÉTECTÉE',
        description: 'Zone Europe : +200ms sur l\'inférence.',
        timestamp: new Date().toLocaleTimeString(),
        impact: 'Fluidité réduite pour 12 sessions actives.'
      }]);
    }, 2000);
    return () => clearTimeout(timer);
  }, []);

  useEffect(() => {
    scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
  }, [messages, isTyping]);

  const handleSend = async () => {
    if (!input.trim() || isTyping) return;
    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsTyping(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      let sys = activeTab === 'autopilot' ? FIKO_SEMI_AUTOPILOT_PROMPT : isCrisisMode ? FIKO_CRISIS_ALERT_PROMPT : FIKO_SUPER_ADMIN_PROMPT;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [...messages, { role: 'user', text: userMsg }].map(m => ({ role: m.role, parts: [{ text: m.text }] })),
        config: { systemInstruction: sys, temperature: 0.5 }
      });
      setMessages(prev => [...prev, { role: 'model', text: response.text || "Diagnostic complet." }]);
    } catch (e) {
      setMessages(prev => [...prev, { role: 'model', text: "Liaison interrompue." }]);
    } finally {
      setIsTyping(false);
    }
  };

  const applyOptimization = (id: string) => {
    setOptimizations(prev => prev.map(o => o.id === id ? { ...o, status: 'applied' } : o));
    setMessages(prev => [...prev, { role: 'model', text: `Décision stratégique ${id} validée. Exécution immédiate sur le noyau de production.` }]);
