    visitors: 1000,
    baseConv: 4,
    boostConv: 6,
    basePrice: 1000000,
    discount: 5
  });

  useEffect(() => {
    const timer = setTimeout(() => {
      setLoading(false);
      setMessages([{
        role: 'model',
        text: `Commandement Super Admin actif. Moteur ROI et Pipeline Prédictif synchronisés. Je suis prêt à simuler l'impact de vos prochaines décisions.`
      }]);
      setDiscountTokens([
        { id: '1', code: 'MARS-72H-5', percent: 5, offer: 'MARS', expiresAt: '2026-02-10 14:00', intentScore: 82, status: 'active' },
        { id: '2', code: 'KRYPTON-24H-10', percent: 10, offer: 'KRYPTON', expiresAt: '2026-02-09 18:00', intentScore: 94, status: 'active' }
      ]);
    }, 1500);
    return () => clearTimeout(timer);
  }, []);

  // ROI Calculations
  const roiResults = useMemo(() => {
    const caA = roiSim.visitors * (roiSim.baseConv / 100) * roiSim.basePrice;
    const discountedPrice = roiSim.basePrice * (1 - roiSim.discount / 100);
    const caB = roiSim.visitors * (roiSim.boostConv / 100) * discountedPrice;
    const roi = caA > 0 ? ((caB - caA) / caA) * 100 : 0;
    const netGain = caB - caA;
    return { caA, caB, roi, netGain };
