import { 
  Hexagon, Activity, ShieldCheck, Settings, CreditCard, Send, Bot, User, LogOut, LayoutDashboard,
  Users, TrendingUp, BarChart3, AlertTriangle, ArrowRight, Database, Globe, DoorOpen,
  Crown, Zap, Sparkles, RefreshCw, Cpu, History, Check, Tag, Timer, Ban, Calculator, Target, Flame, TrendingDown
} from 'lucide-react';

interface AdminDashboardPageProps {
  onNavigate: (p: Page) => void;
  user: UserProfile | null;
  onLogout: () => void;
}

const AdminDashboardPage: React.FC<AdminDashboardPageProps> = ({ onNavigate, user, onLogout }) => {
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<'overview' | 'roi' | 'predictive' | 'negotiation' | 'autopilot'>('overview');
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [discountTokens, setDiscountTokens] = useState<DiscountToken[]>([]);
  const [isCrisisMode, setIsCrisisMode] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  // ROI Simulator State
  const [roiSim, setRoiSim] = useState<RoiSimulation>({
    visitors: 1000,
    baseConv: 4,
    boostConv: 6,
    basePrice: 1000000,
    discount: DISCOUNT_RULES.TIERS[1].percent // Default 5%
  });

  useEffect(() => {
    const timer = setTimeout(() => {
      setLoading(false);
      setMessages([{
        role: 'model',
        text: `Commandement Super Admin actif. Moteur ROI et Pipeline Prédictif synchronisés. Je suis prêt à simuler l'impact de vos prochaines décisions stratégiques.`
      }]);
      setDiscountTokens([
        { id: '1', code: 'MARS-72H-5', percent: 5, offer: 'MARS', expiresAt: '2026-02-10 14:00', intentScore: 82, status: 'active' },
        { id: '2', code: 'KRYPTON-24H-10', percent: 10, offer: 'KRYPTON', expiresAt: '2026-02-09 18:00', intentScore: 94, status: 'active' }
      ]);
    }, 1500);
    return () => clearTimeout(timer);
  }, []);

  // ROI Calculations
  const roiResults = useMemo(() => {
    const caA = roiSim.visitors * (roiSim.baseConv / 100) * roiSim.basePrice;
    const discountedPrice = roiSim.basePrice * (1 - roiSim.discount / 100);
    const caB = roiSim.visitors * (roiSim.boostConv / 100) * discountedPrice;
    const roi = caA > 0 ? ((caB - caA) / caA) * 100 : 0;
    const netGain = caB - caA;
    return { caA, caB, roi, netGain };
  }, [roiSim]);

  const handleSend = async () => {
    if (!input.trim() || isTyping) return;
    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsTyping(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      let sys = activeTab === 'roi' ? FIKO_ROI_ENGINE_PROMPT : activeTab === 'predictive' ? FIKO_PREDICTIVE_PROMPT : FIKO_SUPER_ADMIN_PROMPT;
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [...messages, { role: 'user', text: userMsg }].map(m => ({ role: m.role, parts: [{ text: m.text }] })),
        config: { systemInstruction: sys, temperature: 0.5 }
      });
      setMessages(prev => [...prev, { role: 'model', text: response.text || "Analyse terminée." }]);
    } catch (e) {
      setMessages(prev => [...prev, { role: 'model', text: "Liaison interrompue." }]);
    } finally {
      setIsTyping(false);
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-[#0B0B0F] flex flex-col items-center justify-center gap-8">
        <Hexagon size={80} className="text-[#E10600] animate-spin" />
        <p className="text-[10px] font-black uppercase tracking-[0.6em] text-[#E10600]">Synchronisation du Noyau CEO...</p>
      </div>
    );
  }

  return (
    <div className={`min-h-screen ${isCrisisMode ? 'bg-[#120505]' : 'bg-[#0B0B0F]'} text-white flex overflow-hidden font-sans`}>
      {/* SIDEBAR */}
      <aside className="w-20 lg:w-72 bg-[#121217] border-r border-white/5 flex flex-col z-50">
        <div className="p-8 border-b border-white/5 flex items-center gap-4">
          <div className="size-10 bg-[#E10600] rounded-sm flex items-center justify-center shadow-lg"><Crown size={20} /></div>
          <div className="hidden lg:block">
            <p className="font-black uppercase tracking-tighter text-lg leading-none">KRYPTON <span className="text-[#E10600]">CEO</span></p>
            <p className="text-[7px] font-black text-slate-500 uppercase tracking-widest mt-1">Super Admin Access</p>
          </div>
        </div>
        <nav className="flex-grow py-8 px-4 space-y-2">
          {[
            { id: 'overview', label: 'Vue Globale', icon: <LayoutDashboard size={18} /> },
            { id: 'roi', label: 'ROI Simulator', icon: <Calculator size={18} /> },
            { id: 'predictive', label: 'Pipeline Prédictif', icon: <Target size={18} /> },
            { id: 'negotiation', label: 'Remises FIKO', icon: <Tag size={18} /> },
            { id: 'autopilot', label: 'Semi-Autopilot', icon: <Cpu size={18} /> },
          ].map(item => (
            <button key={item.id} onClick={() => setActiveTab(item.id as any)} className={`w-full flex items-center gap-6 p-4 rounded-sm transition-all ${activeTab === item.id ? 'bg-[#E10600] text-white' : 'text-slate-500 hover:bg-white/5'}`}>
              {item.icon}
              <span className="hidden lg:block text-[9px] font-black uppercase tracking-[0.2em]">{item.label}</span>
            </button>
          ))}
        </nav>
        <div className="p-8 border-t border-white/5"><button onClick={onLogout} className="w-full flex items-center gap-6 p-4 text-[#E10600]"><LogOut size={18} /><span className="hidden lg:block text-[9px] font-black uppercase tracking-widest">Quitter</span></button></div>
      </aside>

      <main className="flex-grow flex flex-col overflow-hidden relative">
        <header className="h-24 bg-[#0B0B0F]/80 backdrop-blur-md border-b border-white/5 px-10 flex items-center justify-between z-40">
           <div className="flex items-center gap-6">
              <div className="px-4 py-2 bg-emerald-500/10 border border-emerald-500/30 text-emerald-500 text-[8px] font-black uppercase tracking-widest rounded-full flex items-center gap-2">
                 <Activity size={12} className="animate-pulse" /> ÉTAT : OPÉRATIONNEL
              </div>
           </div>
           <div className="flex items-center gap-8">
              <p className="text-xs font-mono font-bold text-white uppercase">{user?.firstName} (CEO)</p>
              <div className="size-12 bg-[#1A1A1F] border border-white/10 rounded-full flex items-center justify-center">
                 <User size={24} className="text-slate-600" />
              </div>
           </div>
        </header>

        <div className="flex-grow overflow-y-auto p-10 custom-scrollbar relative z-10">
          <div className="max-w-7xl mx-auto space-y-12">

            {activeTab === 'roi' && (
              <div className="space-y-12 animate-in fade-in duration-700">
                <div className="space-y-2">
                  <h3 className="text-4xl font-black uppercase tracking-tighter">ROI <span className="text-[#E10600]">SIMULATOR.</span></h3>
                  <p className="text-[10px] font-black text-slate-500 uppercase tracking-[0.4em]">VALIDEZ LA RENTABILITÉ DE VOS REMISES AVANT ACTIVATION.</p>
                </div>

                <div className="grid lg:grid-cols-3 gap-8">
                  <div className="lg:col-span-1 bg-[#1A1A1F] p-8 border border-white/5 space-y-8 rounded-sm">
                    <h4 className="text-[10px] font-black uppercase tracking-widest text-[#E10600]">Paramètres de Simulation</h4>
                    <div className="space-y-6">
                      <div className="space-y-3">
                        <label className="text-[9px] font-bold text-slate-500 uppercase">Volume Prospects</label>
                        <input type="number" value={roiSim.visitors} onChange={e => setRoiSim({...roiSim, visitors: +e.target.value})} className="w-full bg-black border border-white/10 p-4 text-xs font-mono text-white" />
                      </div>
                      <div className="space-y-3">
                        <label className="text-[9px] font-bold text-slate-500 uppercase">Conv. sans remise (%)</label>
                        <input type="number" value={roiSim.baseConv} onChange={e => setRoiSim({...roiSim, baseConv: +e.target.value})} className="w-full bg-black border border-white/10 p-4 text-xs font-mono text-white" />
                      </div>
