function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

interface VocalSalesOverlayProps {
  agent: Agent | null;
  onClose: () => void;
  onOpenCheckout: (porte: string) => void;
  initialPorte?: string;
  initialFlowStep?: FikoFlowStep;
}

const VocalSalesOverlay: React.FC<VocalSalesOverlayProps> = ({ agent, onClose, onOpenCheckout, initialPorte, initialFlowStep }) => {
  const [step, setStep] = useState<'pre_start' | 'connecting' | 'active'>('pre_start');
  const [flowStep, setFlowStep] = useState<FikoFlowStep>(initialFlowStep || FikoFlowStep.DISCOVERY);
  const [isActive, setIsActive] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [bars, setBars] = useState<number[]>(new Array(40).fill(5));
  const [leadScore, setLeadScore] = useState(initialPorte ? 60 : 0);
  const [closingProb, setClosingProb] = useState(0); 
  const [transcription, setTranscription] = useState("");
  const [discount, setDiscount] = useState<DiscountToken | null>(null);
  const [timeLeft, setTimeLeft] = useState<number>(0);
  const [selectedPorte, setSelectedPorte] = useState(initialPorte || "MARS");
  const [isUltimateCloser, setIsUltimateCloser] = useState(false);

  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  useEffect(() => {
    let interval: number;
    if (discount && timeLeft > 0) {
      interval = window.setInterval(() => { 
        setTimeLeft(t => {
          if (t <= 1) { setDiscount(null); return 0; }
          return t - 1;
        }); 
      }, 1000);
    }
    return () => window.clearInterval(interval);
  }, [discount, timeLeft]);

  useEffect(() => {
      const prob = Math.min(leadScore * 1.1, 100);
      setClosingProb(prob);

      // Trigger Negotiation automatically
      if (prob >= DISCOUNT_RULES.INTENT_THRESHOLD && flowStep === FikoFlowStep.DISCOVERY && !discount) {
          let tierIndex = 2; // 3%
          if (prob >= 90) tierIndex = 0; // 10%
          else if (prob >= 80) tierIndex = 1; // 5%
          setTimeout(() => triggerNegotiation(tierIndex), 2500);
      }

      // ACTIVATE ULTIMATE CLOSER MODE (Prompt Swap)
      if (prob >= 85 && !isUltimateCloser) {
         setIsUltimateCloser(true);
         sessionRef.current?.sendRealtimeInput([{ 
           text: "ACTION SYSTÈME: Lead BURNING détecté. Bascule immédiate sur le prompt DEAL CLOSER ULTIME. Terminer la vente avec autorité et élégance." 
         }]);
      }
  }, [leadScore, flowStep, discount, isUltimateCloser]);

  const stopSession = useCallback(() => {
    setIsActive(false);
    sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
    sourcesRef.current.clear();
    if (inputAudioContextRef.current?.state !== 'closed') inputAudioContextRef.current?.close().catch(() => {});
    if (outputAudioContextRef.current?.state !== 'closed') outputAudioContextRef.current?.close().catch(() => {});
    if (sessionRef.current) try { sessionRef.current.close(); } catch(e) {}
    setBars(new Array(40).fill(5));
  }, []);

  const startVocalSession = async () => {
    setStep('connecting');
    setError(null);
    try {
      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      if (inputCtx.state === 'suspended') await inputCtx.resume();
      if (outputCtx.state === 'suspended') await outputCtx.resume();
      inputAudioContextRef.current = inputCtx;
      outputAudioContextRef.current = outputCtx;
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setStep('active'); setIsActive(true);
            const source = inputCtx.createMediaStreamSource(stream);
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              if (!isActive) return;
              const inputData = e.inputBuffer.getChannelData(0);
              const volume = inputData.reduce((acc, v) => acc + Math.abs(v), 0) / inputData.length;
              setBars(prev => prev.map(() => Math.floor(Math.random() * (volume * 800 + 5)) + 5));
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              const pcmBlob = { data: encode(new Uint8Array(int16.buffer)), mimeType: 'audio/pcm;rate=16000' };
              sessionPromise.then(s => s.sendRealtimeInput({ media: pcmBlob }));
            };
            source.connect(scriptProcessor); scriptProcessor.connect(inputCtx.destination);
          },
          onmessage: async (m: LiveServerMessage) => {
            if (m.serverContent?.inputTranscription) setTranscription(m.serverContent.inputTranscription.text);
            const base64 = m.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64 && outputCtx.state !== 'closed') {
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputCtx.currentTime);
              const buffer = await decodeAudioData(decode(base64), outputCtx, 24000, 1);
              const source = outputCtx.createBufferSource(); source.buffer = buffer; source.connect(outputCtx.destination);
              source.onended = () => { sourcesRef.current.delete(source); if (sourcesRef.current.size === 0) setBars(new Array(40).fill(5)); };
              source.start(nextStartTimeRef.current); nextStartTimeRef.current += buffer.duration; sourcesRef.current.add(source);
              setLeadScore(prev => Math.min(prev + 5, 100));
            }
          },
          onerror: () => { setError("LIAISON INTERROMPUE."); stopSession(); }
        },
        config: {
          responseModalities: [Modality.AUDIO], inputAudioTranscription: {},
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } } },
          systemInstruction: isUltimateCloser ? FIKO_ULTIMATE_CLOSER_PROMPT : FIKO_NEGOTIATOR_PROMPT + `\nLe client cible la PORTE ${selectedPorte}.`
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (e) { setError("ACCÈS MICRO REFUSÉ."); setStep('pre_start'); }
  };

  const triggerNegotiation = (tierIndex: number) => {
    const tier = DISCOUNT_RULES.TIERS[tierIndex];
    setFlowStep(FikoFlowStep.NEGOTIATION);
    const token = `KRYPTON-${tier.percent}PCT-${Math.random().toString(36).substr(2, 4).toUpperCase()}`;
    setDiscount({ id: 'D' + Date.now(), code: token, offer: selectedPorte, percent: tier.percent, expiresAt: '', intentScore: leadScore, status: 'active' });
    setTimeLeft(1800);
    sessionRef.current?.sendRealtimeInput([{ text: `ACTION SYSTÈME: Score d'intention stratégique validé (${closingProb.toFixed(0)}%). Application immédiate de la remise ${tier.label} (${tier.percent}%). Token unique : ${token}.` }]);
  };

  const formatTime = (seconds: number) => `${Math.floor(seconds / 60)}:${(seconds % 60).toString().padStart(2, '0')}`;

  if (!agent) return null;

  return (
    <div className="fixed inset-0 z-[100] bg-black flex flex-col items-center justify-center p-6 overflow-hidden animate-in fade-in duration-700">
      <div className="absolute inset-0 hex-bg opacity-10"></div>
      <button onClick={onClose} className="absolute top-10 right-10 z-[110] size-16 flex items-center justify-center bg-white/5 border border-white/10 rounded-full hover:bg-white hover:text-black transition-all group">
        <X size={32} className="group-hover:rotate-90 transition-transform" />
      </button>

      {isActive && (
        <div className="absolute top-12 left-10 z-50 flex flex-col gap-3">
           <div className={`flex items-center gap-4 px-6 py-2 border rounded-full backdrop-blur-md transition-all ${isUltimateCloser ? 'bg-[#E10600]/20 border-[#E10600]/50' : 'bg-black/50 border-white/10'}`}>
              <Flame size={16} className={closingProb > 75 ? 'text-[#E10600] animate-pulse' : 'text-slate-500'} />
              <span className={`text-[10px] font-black uppercase tracking-widest ${isUltimateCloser ? 'text-white' : 'text-slate-300'}`}>{isUltimateCloser ? 'DEAL CLOSER ULTIME ACTIF' : `INTENTION : ${closingProb.toFixed(0)}%`}</span>
           </div>
           <div className="w-full h-1 bg-white/5 rounded-full overflow-hidden">
              <div className={`h-full transition-all duration-1000 ${closingProb > 85 ? 'bg-white' : closingProb > 75 ? 'bg-[#E10600]' : 'bg-slate-500'}`} style={{ width: `${closingProb}%` }}></div>
           </div>
        </div>
      )}

      {step === 'pre_start' && (
        <div className="text-center space-y-16 relative z-10">
          <Hexagon size={120} className="text-[#E10600] animate-[spin_10s_linear_infinite] mx-auto" strokeWidth={1} />
          <h2 className="text-6xl lg:text-[100px] font-black uppercase tracking-tighter text-white leading-none">FIKO <span className="text-[#E10600]">NEGOTIATOR.</span></h2>
          <button onClick={startVocalSession} className="bg-[#E10600] text-white px-16 py-8 font-black text-xs uppercase tracking-[0.5em] shadow-2xl flex items-center gap-6 mx-auto hover:scale-105 active:scale-95 transition-all">🎙️ INITIALISER LE CLOSING</button>
        </div>
      )}

      {step === 'active' && (
        <div className="flex flex-col items-center justify-center h-full w-full max-w-5xl relative">
           <div className="relative z-10 flex items-center justify-center gap-2 h-48 w-full mb-10">
             {bars.map((h, i) => <div key={i} className={`w-2 md:w-3 rounded-full transition-all duration-150 ${isUltimateCloser ? 'bg-white' : 'bg-[#E10600]'}`} style={{ height: `${h}%`, opacity: (h / 100) * 0.5 + 0.5 }}></div>)}
           </div>

           {discount && (
              <div className="bg-white p-10 rounded-sm shadow-[0_0_120px_rgba(255,255,255,0.2)] animate-in slide-in-from-top-12 border-t-8 border-[#E10600] w-full max-w-md relative group/card">
                <div className="absolute -top-14 left-1/2 -translate-x-1/2 flex items-center gap-4 bg-black border border-white/10 px-8 py-3 rounded-full shadow-2xl">
                   <Timer className="animate-pulse text-[#E10600]" size={20} />
                   <span className="text-2xl font-mono font-black text-white">{formatTime(timeLeft)}</span>
                </div>
                <div className="flex justify-between items-center mb-6">
                   <div className="bg-[#E10600] text-white px-5 py-2 text-[10px] font-black uppercase tracking-widest flex items-center gap-3"><Zap size={14} fill="white" /> OFFRE CLOSING AUTOMATIQUE</div>
                   <ShieldCheck className="text-[#E10600]" size={24} />
                </div>
                <h4 className="text-black text-4xl font-black uppercase tracking-tighter mb-4 leading-none">REMISE DE {discount.percent}% ACTIVÉE</h4>
                <div className="mt-8 pt-6 border-t border-slate-100 flex items-center justify-between">
                   <div className="space-y-1"><p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">TOKEN_ID</p><p className="font-mono text-xs text-black font-black">{discount.code}</p></div>
                   <Tag className="text-[#E10600]" size={20} />
                </div>
              </div>
           )}

           <div className="mt-16 text-center space-y-12 relative z-20 w-full max-w-lg">
              {flowStep === FikoFlowStep.DISCOVERY && (
                 <div className="space-y-4 animate-in fade-in duration-1000">
                    <p className="text-xl text-slate-400 font-light italic leading-relaxed">"FIKO™ analyse la maturité de votre projet..."</p>
                    <div className="flex justify-center gap-2">
                       <div className="size-1.5 bg-[#E10600] rounded-full animate-bounce [animation-delay:0s]"></div>
                       <div className="size-1.5 bg-[#E10600] rounded-full animate-bounce [animation-delay:0.2s]"></div>
                       <div className="size-1.5 bg-[#E10600] rounded-full animate-bounce [animation-delay:0.4s]"></div>
                    </div>
                 </div>
              )}
              {flowStep === FikoFlowStep.NEGOTIATION && (
                <div className="space-y-8 animate-in slide-in-from-bottom-4">
                   <button onClick={() => setFlowStep(FikoFlowStep.ACCOUNT_CREATION)} className={`px-14 py-8 text-[11px] font-black uppercase tracking-[0.4em] hover:scale-105 transition-all shadow-2xl group ${isUltimateCloser ? 'bg-white text-black' : 'bg-[#E10600] text-white'}`}>
                      SÉCURISER CETTE OFFRE <ArrowRight size={20} className="inline ml-4 group-hover:translate-x-3 transition-transform" />
                   </button>
                </div>
              )}
              {transcription && (
                <div className="max-w-2xl mx-auto bg-black/60 border border-white/5 p-8 text-white text-xl italic leading-relaxed rounded-sm backdrop-blur-md animate-in fade-in duration-500 shadow-2xl border-l-4 border-[#E10600]">"{transcription}"</div>
              )}
           </div>
        </div>
      )}

      {error && (
        <div className="fixed bottom-12 left-1/2 -translate-x-1/2 z-[150] bg-[#E10600] border border-white/20 p-10 rounded-sm flex items-center gap-10 shadow-2xl animate-in slide-in-from-bottom-4">
           <AlertTriangle className="text-white" size={48} />
           <div className="space-y-4">
              <p className="text-base font-black uppercase tracking-widest text-white leading-relaxed">{error}</p>
              <button onClick={() => { setError(null); startVocalSession(); }} className="flex items-center gap-4 px-6 py-3 bg-white/10 rounded-full hover:bg-white/20 transition-all text-[10px] font-black uppercase tracking-widest text-white">
                 <RefreshCcw size={18} /> RÉINTÉGRER LA LIAISON
              </button>
           </div>
        </div>
      )}
    </div>
  );
};

