    if (!input.trim() || isTyping) return;
    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsTyping(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      let sys = FIKO_SUPER_ADMIN_PROMPT;
      if (activeTab === 'ltv') sys = FIKO_LTV_ENGINE_PROMPT;
      if (activeTab === 'pricing') sys = FIKO_SMART_PRICING_PROMPT;
      if (activeTab === 'autonomy') sys = FIKO_GUARDED_AUTONOMY_PROMPT;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [...messages, { role: 'user', text: userMsg }].map(m => ({ role: m.role, parts: [{ text: m.text }] })),
        config: { systemInstruction: sys, temperature: 0.5 }
      });
      setMessages(prev => [...prev, { role: 'model', text: response.text || "Analyse terminée." }]);
    } catch (e) {
      setMessages(prev => [...prev, { role: 'model', text: "Liaison interrompue." }]);
