const AdminDashboardPage: React.FC<AdminDashboardPageProps> = ({ onNavigate, user, onLogout }) => {
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<'overview' | 'ltv' | 'pricing' | 'autonomy' | 'analytics'>('overview');
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [selectedRegion, setSelectedRegion] = useState('ALL');

  // Smart Pricing Simulation State
  const [pricingSim, setPricingSim] = useState<PricingSimulation>({ 
    demandIndex: 1, 
    teamLoadIndex: 1, 
    targetLtvIndex: 1 
  });

  // Autonomous Governance Logs
  const [autoActions] = useState<AutonomousAction[]>([
    { id: 'ACT-001', timestamp: 'Il y a 8 min', category: 'UX', description: 'Optimisation micro-copy onboarding Porte MARS.', impactObserved: 'Friction -6%', authorityLevel: 'N1', risk: 'low' },
    { id: 'ACT-002', timestamp: 'Il y a 22 min', category: 'Nego', description: 'Activation Token 5% pour un Lead Gold (Secteur BTP).', impactObserved: 'Closing Prob. +14%', authorityLevel: 'N2', risk: 'medium' },
    { id: 'ACT-003', timestamp: 'Il y a 1h', category: 'Sales', description: 'Relance automatique via Voix FIKO™ (Lead Platinum).', impactObserved: 'Réactivation positive', authorityLevel: 'N1', risk: 'low' },
    { id: 'ACT-004', timestamp: 'Il y a 2h', category: 'UX', description: 'Ajustement latence conversationnelle (+200ms) pour réalisme.', impactObserved: 'Engagement +3%', authorityLevel: 'N1', risk: 'low' },
  ]);

  const scrollRef = useRef<HTMLDivElement>(null);

  // Mock BigQuery Analytics Data
  const analyticsData = [
    { date: '01/02', ca: 12.4, roi: 18, conv: 4.2 },
    { date: '02/02', ca: 15.2, roi: 22, conv: 4.8 },
    { date: '03/02', ca: 14.8, roi: 21, conv: 5.1 },
    { date: '04/02', ca: 18.4, roi: 25, conv: 5.4 },
    { date: '05/02', ca: 22.1, roi: 28, conv: 6.2 },
    { date: '06/02', ca: 21.0, roi: 32, conv: 6.0 },
    { date: '07/02', ca: 25.4, roi: 35, conv: 6.8 },
  ];

  useEffect(() => {
    const timer = setTimeout(() => {
      setLoading(false);
      setMessages([{
        role: 'model',
        text: `Noyau Super Admin v10.0 activé. Moteur BigQuery opérationnel. LTV Engine et Smart Pricing synchronisés. FIKO™ est en mode Autonomie Supervisée (N1/N2).`
      }]);
    }, 1500);
    return () => clearTimeout(timer);
  }, []);

  useEffect(() => {
    scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
  }, [messages, isTyping]);

  const handleSend = async () => {
    if (!input.trim() || isTyping) return;
    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsTyping(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      let systemPrompt = FIKO_SUPER_ADMIN_PROMPT;
      if (activeTab === 'ltv') systemPrompt = FIKO_LTV_ENGINE_PROMPT;
      if (activeTab === 'pricing') systemPrompt = FIKO_SMART_PRICING_PROMPT;
      if (activeTab === 'autonomy') systemPrompt = FIKO_GUARDED_AUTONOMY_PROMPT;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [...messages, { role: 'user', text: userMsg }].map(m => ({ role: m.role, parts: [{ text: m.text }] })),
        config: { systemInstruction: systemPrompt, temperature: 0.4 }
      });
      setMessages(prev => [...prev, { role: 'model', text: response.text || "Analyse terminée." }]);
    } catch (e) {
      setMessages(prev => [...prev, { role: 'model', text: "Liaison interrompue." }]);
    } finally {
      setIsTyping(false);
    }
  };

  const calculatedSmartPrice = useMemo(() => {
    const base = 1000000;
    const demandMod = (pricingSim.demandIndex - 1) * 0.1; // -10% to +10%
    const loadMod = (pricingSim.teamLoadIndex - 1) * 0.05; // -5% to +5%
    const ltvMod = (pricingSim.targetLtvIndex - 1) * -0.05; // High LTV = more flexibility
    const total = base * (1 + demandMod + loadMod + ltvMod);
    // Bornes de sécurité : +15%, -10%
    return Math.max(base * 0.9, Math.min(base * 1.15, Math.round(total / 1000) * 1000));
  }, [pricingSim]);

  if (loading) return (
