  const theme = GATE_THEMES[gate] || GATE_THEMES.MARS;
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<'overview' | 'project' | 'messages' | 'billing'>('overview');
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const timer = setTimeout(() => {
      setLoading(false);
      setMessages([{
        role: 'model',
        text: `Félicitations, votre accès Porte ${gate} est validé. Je suis FIKO™, votre coordinateur de projet. Ma mission est de transformer votre vision en une infrastructure opérationnelle. Par quoi commençons-nous ?`
      }]);
    }, 2000);
    return () => clearTimeout(timer);
  }, [gate]);

  useEffect(() => {
    scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
  }, [messages, isTyping]);

  const handleSend = async () => {
    if (!input.trim() || isTyping) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsTyping(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [...messages, { role: 'user', text: userMsg }].map(m => ({
          role: m.role,
          parts: [{ text: m.text }]
        })),
        config: {
          systemInstruction: FIKO_ONBOARDING_PROMPT + `\nLe client a validé la PORTE ${gate}. Réponds comme un coordinateur projet calme, précis et tourné vers l'exécution.`,
          temperature: 0.7,
        }
      });

      const aiText = response.text || "Synchronisation en cours. Veuillez poursuivre.";
      setMessages(prev => [...prev, { role: 'model', text: aiText }]);
    } catch (error) {
      console.error(error);
      setMessages(prev => [...prev, { role: 'model', text: "Liaison saturée temporairement. Vos données sont en sécurité." }]);
    } finally {
      setIsTyping(false);
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-[#0B0B0F] flex flex-col items-center justify-center gap-8">
