  const [isGenerating, setIsGenerating] = useState(false);
  const [isSending, setIsSending] = useState(false);
  const [campaignSuccess, setCampaignSuccess] = useState(false);
  const [campaignData, setCampaignData] = useState({
    subject: '',
    body: ''
  });

  const chartData = [
    { name: 'Juil', val: 40 },
    { name: 'Août', val: 55 },
    { name: 'Sept', val: 80 },
    { name: 'Oct', val: 70 },
    { name: 'Nov', val: 90 },
    { name: 'Déc', val: 100 },
  ];

  const selectedLeads = useMemo(() => 
    LEADS.filter(l => selectedLeadIds.includes(l.id)),
    [selectedLeadIds]
  );

  const toggleLeadSelection = (id: string) => {
    setSelectedLeadIds(prev => 
      prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]
    );
  };

  const toggleSelectAll = () => {
    if (selectedLeadIds.length === LEADS.length) {
      setSelectedLeadIds([]);
    } else {
      setSelectedLeadIds(LEADS.map(l => l.id));
    }
  };

  const generateAIEmail = async () => {
    if (selectedLeads.length === 0) return;
    setIsGenerating(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const targetEntities = selectedLeads.map(l => l.entity).join(', ');
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Génère un email de relance commerciale ultra-performant pour les entreprises suivantes : ${targetEntities}. 
        Le ton doit être celui de Krypton AI : autoritaire, stratégique et haut de gamme. 
        Focus sur l'activation de la "Porte Krypton" (IA de closing).
        Réponds au format texte avec :
        OBJET: [Sujet]
        CORPS: [Contenu]`,
        config: {
          temperature: 0.8,
        }
      });

      const text = response.text || "";
      const subjectMatch = text.match(/OBJET:\s*(.*)/i);
      const bodyMatch = text.match(/CORPS:\s*([\s\S]*)/i);

      setCampaignData({
        subject: subjectMatch ? subjectMatch[1].trim() : 'Opportunité Stratégique Krypton AI',
        body: bodyMatch ? bodyMatch[1].trim() : text
      });
    } catch (error) {
      console.error('Email Generation Error:', error);
    } finally {
      setIsGenerating(false);
    }
  };

