              <div className="bg-black/90 border border-orange-500 p-12 rounded-sm text-center space-y-8 animate-in zoom-in-95 z-50 max-w-lg">
                 <ShieldAlert className="text-orange-500 size-20 mx-auto animate-pulse" />
                 <h4 className="text-3xl font-black uppercase text-white">LIAISON SUSPENDUE.</h4>
                 <p className="text-slate-400 italic font-light">"FIKO™ a détecté un profil sans pouvoir de décision final. L'accès à Krypton AI est réservé aux décideurs pour préserver la valeur de notre temps."</p>
                 <button onClick={onClose} className="w-full py-6 bg-white text-black font-black text-xs uppercase tracking-widest">Quitter l'Espace</button>
              </div>
           )}

           <div className="mt-16 text-center space-y-12 relative z-20 w-full max-w-lg">
              {fakeDeciderScore >= 30 && fakeDeciderScore < 70 ? (
                <p className="text-2xl text-orange-400 font-black uppercase tracking-tighter animate-pulse">FIKO™ clarifie votre rôle...</p>
              ) : silenceLevel !== SilenceLevel.NONE ? (
                <div className="space-y-6">
                  <p className="text-2xl text-purple-400 font-black uppercase tracking-tighter animate-pulse">Silence Stratégique Actif...</p>
                  <p className="text-sm text-slate-500 italic uppercase tracking-widest">FIKO™ vous laisse la main. Que décidez-vous ?</p>
                </div>
              ) : transcription ? (
                <div className="max-w-2xl mx-auto bg-black/60 border border-white/5 p-8 text-white text-xl italic leading-relaxed rounded-sm backdrop-blur-md shadow-2xl border-l-4 border-[#E10600]">"{transcription}"</div>
              ) : null}
           </div>
        </div>
      )}

      {error && (
        <div className="fixed bottom-12 left-1/2 -translate-x-1/2 z-[150] bg-[#E10600] border border-white/20 p-10 rounded-sm flex items-center gap-10 shadow-2xl animate-in slide-in-from-bottom-4">
           <AlertTriangle className="text-white" size={48} />
           <button onClick={() => { setError(null); startVocalSession(); }} className="flex items-center gap-4 px-6 py-3 bg-white/10 rounded-full hover:bg-white/20 transition-all text-[10px] font-black uppercase text-white">
              <RefreshCcw size={18} /> RÉ-ÉTABLIR LIAISON
           </button>
        </div>
      )}
    </div>
  );
};

