function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

interface VocalSalesOverlayProps {
  agent: Agent | null;
  onClose: () => void;
  onOpenCheckout: (porte: string) => void;
  initialPorte?: string;
  initialFlowStep?: FikoFlowStep;
}

const VocalSalesOverlay: React.FC<VocalSalesOverlayProps> = ({ agent, onClose, onOpenCheckout, initialPorte, initialFlowStep }) => {
  const [step, setStep] = useState<'pre_start' | 'connecting' | 'active'>('pre_start');
  const [flowStep, setFlowStep] = useState<FikoFlowStep>(initialFlowStep || FikoFlowStep.DISCOVERY);
  const [isActive, setIsActive] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [bars, setBars] = useState<number[]>(new Array(40).fill(5));

  // Decision Score State
  const [decisionScore, setDecisionScore] = useState(initialPorte ? 60 : 20);
  const [profile, setProfile] = useState<DecisionProfile>(DecisionProfile.TOURISTE);
  const [silenceLevel, setSilenceLevel] = useState<SilenceLevel>(SilenceLevel.NONE);

  // Fake Decider State
  const [fakeDeciderScore, setFakeDeciderScore] = useState(0);
  const [fakeRisk, setFakeRisk] = useState<FakeDeciderRisk>(FakeDeciderRisk.NONE);

  const [transcription, setTranscription] = useState("");
  const [discount, setDiscount] = useState<DiscountToken | null>(null);
  const [timeLeft, setTimeLeft] = useState<number>(0);
  const [selectedPorte, setSelectedPorte] = useState(initialPorte || "MARS");
  const [isUltimateCloser, setIsUltimateCloser] = useState(false);

  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  // Update profile based on score
  useEffect(() => {
    if (decisionScore < 40) setProfile(DecisionProfile.TOURISTE);
    else if (decisionScore < 60) setProfile(DecisionProfile.INFLUENCEUR);
    else if (decisionScore < 80) setProfile(DecisionProfile.DECIDEUR);
    else setProfile(DecisionProfile.DECIDEUR_IMMEDIAT);

    if (decisionScore >= 85 && !isUltimateCloser && sessionRef.current && fakeDeciderScore < 30) {
      setIsUltimateCloser(true);
      sessionRef.current.send([{ text: "SYSTÈME: Profil DÉCIDEUR IMMÉDIAT validé. Activation Assomption Silencieuse. Token de clôture prêt." }]);
    }

    if (decisionScore >= 75 && flowStep === FikoFlowStep.DISCOVERY && !discount && fakeDeciderScore < 30) {
      triggerNegotiation(0);
    }
  }, [decisionScore, isUltimateCloser, fakeDeciderScore]);

  // Fake Decider Detection Logic
  useEffect(() => {
    const text = transcription.toLowerCase();
    let penalty = 0;
    if (text.includes("parler à") || text.includes("demander à")) penalty += 20;
    if (text.includes("voir en interne") || text.includes("comité")) penalty += 20;
    if (text.includes("pas moi qui décide") || text.includes("pas moi qui signe")) penalty += 30;

    if (penalty > 0) {
      setFakeDeciderScore(prev => Math.min(prev + penalty, 100));
    }
  }, [transcription]);

  useEffect(() => {
    if (fakeDeciderScore >= 70) setFakeRisk(FakeDeciderRisk.EXIT);
    else if (fakeDeciderScore >= 50) setFakeRisk(FakeDeciderRisk.CONFIRMED);
    else if (fakeDeciderScore >= 30) setFakeRisk(FakeDeciderRisk.SUSPECT);
    else setFakeRisk(FakeDeciderRisk.NONE);

    if (fakeDeciderScore >= 75 && isActive) {
      // Elegant Exit triggered logic
    }
  }, [fakeDeciderScore, isActive]);

  // Silence Stratégique Logic
  useEffect(() => {
    if (transcription.toLowerCase().includes("réfléchir") || transcription.toLowerCase().includes("voir plus tard")) {
      if (decisionScore >= 60 && silenceLevel === SilenceLevel.NONE) {
        triggerSilence(SilenceLevel.REFLEXIVE);
      }
    }
  }, [transcription]);

  const triggerSilence = (level: SilenceLevel) => {
    setSilenceLevel(level);
    setTimeout(() => {
      if (level === SilenceLevel.SHORT) setSilenceLevel(SilenceLevel.NONE);
    }, 5000);
  };

  useEffect(() => {
    let interval: number;
    if (discount && timeLeft > 0) {
      interval = window.setInterval(() => { 
        setTimeLeft(t => {
          if (t <= 1) { setDiscount(null); return 0; }
          return t - 1;
        }); 
      }, 1000);
    }
    return () => window.clearInterval(interval);
  }, [discount, timeLeft]);

  const stopSession = useCallback(() => {
    setIsActive(false);
    sourcesRef.current.forEach(s => { try { s.stop(); } catch(e) {} });
    sourcesRef.current.clear();
    if (inputAudioContextRef.current?.state !== 'closed') inputAudioContextRef.current?.close().catch(() => {});
    if (outputAudioContextRef.current?.state !== 'closed') outputAudioContextRef.current?.close().catch(() => {});
    if (sessionRef.current) try { sessionRef.current.close(); } catch(e) {}
    setBars(new Array(40).fill(5));
    setSilenceLevel(SilenceLevel.NONE);
  }, []);

  const startVocalSession = async () => {
    setStep('connecting');
    setError(null);
    try {
      const AudioContextClass = (window as any).AudioContext || (window as any).webkitAudioContext;
      if (!AudioContextClass) throw new Error("AudioContext not supported");

      let inputCtx: AudioContext;
      let outputCtx: AudioContext;

      try {
        inputCtx = new AudioContextClass({ sampleRate: 16000 });
        outputCtx = new AudioContextClass({ sampleRate: 24000 });
      } catch (e) {
        inputCtx = new AudioContextClass();
        outputCtx = new AudioContextClass();
      }

      if (inputCtx.state === 'suspended') await inputCtx.resume();
      if (outputCtx.state === 'suspended') await outputCtx.resume();
      inputAudioContextRef.current = inputCtx;
      outputAudioContextRef.current = outputCtx;
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setStep('active'); setIsActive(true);
            const source = inputCtx.createMediaStreamSource(stream);
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (audioProcessingEvent) => {
              if (!isActive || silenceLevel !== SilenceLevel.NONE) return;
              const inputData = audioProcessingEvent.inputBuffer.getChannelData(0);
              const volume = inputData.reduce((acc, v) => acc + Math.abs(v), 0) / inputData.length;
              setBars(prev => prev.map(() => Math.floor(Math.random() * (volume * 800 + 5)) + 5));
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              const pcmBlob = { data: encode(new Uint8Array(int16.buffer)), mimeType: 'audio/pcm;rate=16000' };
              sessionPromise.then(s => s.sendRealtimeInput({ media: pcmBlob }));
            };
            source.connect(scriptProcessor); scriptProcessor.connect(inputCtx.destination);
          },
          onmessage: async (m: LiveServerMessage) => {
            if (m.serverContent?.inputTranscription) setTranscription(m.serverContent.inputTranscription.text);
            const base64 = m.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64 && outputCtx.state !== 'closed') {
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputCtx.currentTime);
              const buffer = await decodeAudioData(decode(base64), outputCtx, 24000, 1);
              const source = outputCtx.createBufferSource(); source.buffer = buffer; source.connect(outputCtx.destination);
              source.onended = () => { sourcesRef.current.delete(source); if (sourcesRef.current.size === 0) setBars(new Array(40).fill(5)); };
              source.start(nextStartTimeRef.current); nextStartTimeRef.current += buffer.duration; sourcesRef.current.add(source);

              setDecisionScore(prev => Math.min(prev + (Math.random() * 5), 100));
              setSilenceLevel(SilenceLevel.NONE); 
            }
          },
          onerror: () => { setError("LIAISON INTERROMPUE."); stopSession(); }
        },
        config: {
          responseModalities: [Modality.AUDIO], inputAudioTranscription: {},
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } } },
          systemInstruction: isUltimateCloser ? FIKO_ULTIMATE_CLOSER_PROMPT : FIKO_NEGOTIATOR_PROMPT + `\nDIRECTIVE : Calcule le Score Décideur, applique le Silence Stratégique et DÉTECTE LES FAUX DÉCIDEURS.`
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (e) { setError("ACCÈS MICRO REFUSÉ."); setStep('pre_start'); }
  };

  const triggerNegotiation = (tierIndex: number) => {
    const tier = DISCOUNT_RULES.TIERS[tierIndex];
    setFlowStep(FikoFlowStep.NEGOTIATION);
    const token = `KRYPTON-${tier.percent}PCT-${Math.random().toString(36).substr(2, 4).toUpperCase()}`;
    setDiscount({ id: 'D' + Date.now(), code: token, offer: selectedPorte, percent: tier.percent, expiresAt: '', intentScore: decisionScore, status: 'active' });
    setTimeLeft(1800);
  };

  const formatTime = (seconds: number) => `${Math.floor(seconds / 60)}:${(seconds % 60).toString().padStart(2, '0')}`;

  if (!agent) return null;

  return (
    <div className="fixed inset-0 z-[100] bg-black flex flex-col items-center justify-center p-6 overflow-hidden animate-in fade-in duration-700">
      <div className="absolute inset-0 hex-bg opacity-10"></div>
      <button onClick={onClose} className="absolute top-10 right-10 z-[110] size-16 flex items-center justify-center bg-white/5 border border-white/10 rounded-full hover:bg-white hover:text-black transition-all group">
        <X size={32} className="group-hover:rotate-90 transition-transform" />
      </button>

      {isActive && (
        <div className="absolute top-12 left-10 z-50 flex flex-col gap-6 w-72">
           <div className={`flex items-center gap-4 px-6 py-2 border rounded-full backdrop-blur-md transition-all ${decisionScore > 75 ? 'bg-[#E10600]/20 border-[#E10600]/50' : 'bg-black/50 border-white/10'}`}>
              {decisionScore < 40 ? <Filter size={16} className="text-slate-500" /> : <Target size={16} className="text-[#E10600] animate-pulse" />}
              <span className="text-[10px] font-black uppercase tracking-widest text-white">{profile} : {decisionScore.toFixed(0)}%</span>
           </div>

           <div className={`flex items-center gap-4 px-6 py-2 border rounded-full backdrop-blur-md transition-all ${fakeDeciderScore > 30 ? 'bg-orange-500/20 border-orange-500/50 text-orange-400' : 'bg-black/50 border-white/10 text-slate-500'}`}>
              {fakeDeciderScore > 50 ? <VenetianMask size={16} className="animate-pulse" /> : <UserMinus size={16} />}
              <span className="text-[10px] font-black uppercase tracking-widest">Risque Imposteur : {fakeRisk}</span>
           </div>

           {silenceLevel !== SilenceLevel.NONE && (
             <div className="animate-in slide-in-from-left-4 duration-500 flex items-center gap-4 px-6 py-2 bg-purple-500/20 border border-purple-500/50 rounded-full text-purple-400">
                <EyeOff size={16} className="animate-pulse" />
                <span className="text-[9px] font-black uppercase tracking-[0.2em]">Pression Stratégique Active (N{silenceLevel})</span>
             </div>
           )}

           <div className="w-full h-1 bg-white/5 rounded-full overflow-hidden">
              <div className={`h-full transition-all duration-1000 ${decisionScore >= 80 ? 'bg-[#E10600]' : decisionScore >= 60 ? 'bg-emerald-500' : 'bg-slate-500'}`} style={{ width: `${decisionScore}%` }}></div>
           </div>
        </div>
      )}

      {step === 'pre_start' && (
        <div className="text-center space-y-16 relative z-10">
          <Hexagon size={120} className="text-[#E10600] animate-[spin_10s_linear_infinite] mx-auto" strokeWidth={1} />
          <h2 className="text-6xl lg:text-[100px] font-black uppercase tracking-tighter text-white leading-none">FIKO <span className="text-[#E10600]">AUTHORITY.</span></h2>
          <button onClick={startVocalSession} className="bg-[#E10600] text-white px-16 py-8 font-black text-xs uppercase tracking-[0.5em] shadow-2xl flex items-center gap-6 mx-auto hover:scale-105 transition-all">🎙️ INITIALISER LE DIAGNOSTIC</button>
        </div>
      )}

      {step === 'active' && (
        <div className="flex flex-col items-center justify-center h-full w-full max-w-5xl relative">
           <div className="relative z-10 flex items-center justify-center gap-2 h-48 w-full mb-10">
             {bars.map((h, i) => (
               <div 
                key={i} 
                className={`w-2 md:w-3 rounded-full transition-all duration-150 ${fakeDeciderScore >= 50 ? 'bg-orange-900/50' : silenceLevel !== SilenceLevel.NONE ? 'bg-purple-900/50' : isUltimateCloser ? 'bg-white' : 'bg-[#E10600]'}`} 
                style={{ 
                  height: (fakeDeciderScore >= 50 || silenceLevel !== SilenceLevel.NONE) ? '10%' : `${h}%`, 
                  opacity: (h / 100) * 0.5 + 0.5 
                }}
               ></div>
             ))}
           </div>

           {fakeDeciderScore >= 70 && (
              <div className="bg-black/90 border border-orange-500 p-12 rounded-sm text-center space-y-8 animate-in zoom-in-95 z-50 max-w-lg">
                 <ShieldAlert className="text-orange-500 size-20 mx-auto animate-pulse" />
                 <h4 className="text-3xl font-black uppercase text-white">LIAISON SUSPENDUE.</h4>
                 <p className="text-slate-400 italic font-light">"FIKO™ a détecté un profil sans pouvoir de décision final. L'accès à Krypton AI est réservé aux décideurs pour préserver la valeur de notre temps."</p>
                 <button onClick={onClose} className="w-full py-6 bg-white text-black font-black text-xs uppercase tracking-widest">Quitter l'Espace</button>
              </div>
           )}

           <div className="mt-16 text-center space-y-12 relative z-20 w-full max-w-lg">
              {fakeDeciderScore >= 30 && fakeDeciderScore < 70 ? (
                <p className="text-2xl text-orange-400 font-black uppercase tracking-tighter animate-pulse">FIKO™ clarifie votre rôle...</p>
              ) : silenceLevel !== SilenceLevel.NONE ? (
                <div className="space-y-6">
                  <p className="text-2xl text-purple-400 font-black uppercase tracking-tighter animate-pulse">Silence Stratégique Actif...</p>
                  <p className="text-sm text-slate-500 italic uppercase tracking-widest">FIKO™ vous laisse la main. Que décidez-vous ?</p>
                </div>
              ) : transcription ? (
                <div className="max-w-2xl mx-auto bg-black/60 border border-white/5 p-8 text-white text-xl italic leading-relaxed rounded-sm backdrop-blur-md shadow-2xl border-l-4 border-[#E10600]">"{transcription}"</div>
              ) : null}
           </div>
        </div>
      )}

      {error && (
        <div className="fixed bottom-12 left-1/2 -translate-x-1/2 z-[150] bg-[#E10600] border border-white/20 p-10 rounded-sm flex items-center gap-10 shadow-2xl animate-in slide-in-from-bottom-4">
           <AlertTriangle className="text-white" size={48} />
           <button onClick={() => { setError(null); startVocalSession(); }} className="flex items-center gap-4 px-6 py-3 bg-white/10 rounded-full hover:bg-white/20 transition-all text-[10px] font-black uppercase text-white">
              <RefreshCcw size={18} /> RÉ-ÉTABLIR LIAISON
           </button>
        </div>
      )}
    </div>
  );
};

